function selfReflectionLoop(code, options = {}) {
  options = options || {};
  const maxIterations = options.maxIterations || 5;
  const threshold = options.threshold || 0.8;
  const evaluate = options.evaluate || function() { return { score: 1, issues: [] }; };
  const refine = options.refine || function(c) { return c; };

  let current = code;
  const history = [];
  const iteration = 0;
  let converged = false;

  while (iteration < maxIterations) {
    const evaluation = evaluate(current, iteration);
    const score = typeof evaluation.score === 'number' ? evaluation.score : 0;
    const issues = evaluation.issues || [];

    history.push({
      iteration: iteration,
      score: score,
      issues: issues.slice(),
      codeLength: current.length
    });

    if (score >= threshold) {
      converged = true;
      break;
    }

    if (iteration > 0 && history[iteration].score <= history[iteration - 1].score) {
      break;
    }

    const refined = refine(current, issues, iteration);
    if (refined === current) break;

    current = refined;
    iteration++;
  }

  return {
    code: current,
    converged: converged,
    iterations: history.length,
    finalScore: history.length > 0 ? history[history.length - 1].score : 0,
    history: history,
    improved: history.length > 1 && history[history.length - 1].score > history[0].score
  };
}

