function MinHeap() { this.data = []; }
MinHeap.prototype.insert = function(val) {
  this.data.push(val);
  let i = this.data.length - 1;
  while (i > 0) {
    let p = (i - 1) >>> 1;
    if (this.data[p] <= this.data[i]) break;
    let t = this.data[p]; this.data[p] = this.data[i]; this.data[i] = t;
    i = p;
  }
};
MinHeap.prototype.extractMin = function() {
  if (!this.data.length) return undefined;
  let min = this.data[0], last = this.data.pop();
  if (this.data.length > 0) {
    this.data[0] = last;
    let i = 0, n = this.data.length;
    while (true) {
      let m = i, l = 2*i+1, r = 2*i+2;
      if (l < n && this.data[l] < this.data[m]) m = l;
      if (r < n && this.data[r] < this.data[m]) m = r;
      if (m === i) break;
      let t = this.data[i]; this.data[i] = this.data[m]; this.data[m] = t;
      i = m;
    }
  }
  return min;
};
MinHeap.prototype.peek = function() { return this.data[0]; };

