function generateHealingPRComment(analysis: any) {
  if (!analysis) throw new Error('analysis required');

  let patternName = analysis.patternName || 'unknown';
  let before = analysis.beforeScore || 0;
  let after = analysis.afterScore || 0;
  let delta = Math.round((after - before) * 1000) / 1000;
  let method = analysis.method || 'iterative-refine';
  let issues = analysis.issuesFixed || [];
  let breaking = analysis.breakingChanges || false;

  let emoji = delta > 0.15 ? '**major**' : delta > 0.05 ? 'moderate' : delta > 0 ? 'minor' : 'neutral';

  let lines = [];
  lines.push('## Pattern Healing Report');
  lines.push('');
  lines.push('**Pattern**: ' + patternName);
  lines.push('**Method**: ' + method);
  lines.push('**Score**: ' + before.toFixed(3) + ' -> ' + after.toFixed(3) + ' (delta: ' + (delta >= 0 ? '+' : '') + delta.toFixed(3) + ')');
  lines.push('**Impact**: ' + emoji);
  lines.push('');

  if (issues.length > 0) {
    lines.push('### Issues Fixed');
    for (let i = 0; i < issues.length; i++) {
      lines.push('- ' + issues[i]);
    }
    lines.push('');
  }

  if (breaking) {
    lines.push('> **Warning**: This healing includes breaking changes. Review carefully.');
    lines.push('');
  }

  lines.push('### Verification');
  lines.push('- [ ] Tests pass');
  lines.push('- [ ] Coherency score improved');
  lines.push('- [ ] No regressions in dependent patterns');
  lines.push('');
  lines.push('---');
  lines.push('*Auto-generated by Remembrance Oracle healing pipeline*');

  return lines.join('\n');
}

