    let mut data = vec![3, 1, 4, 1, 5];
    sort_with(&mut data, &BubbleSort);
    assert_eq!(data, vec![1, 1, 3, 4, 5]);

    let mut data2 = vec![5, 4, 3, 2, 1];
    sort_with(&mut data2, &InsertionSort);
    assert_eq!(data2, vec![1, 2, 3, 4, 5]);
}

