function generateLSHSignature(text: string, options = {}: Record<string, any>) {
  options = options || {};
  let numHashes = options.numHashes || 128;
  let shingleSize = options.shingleSize || 3;

  if (!text || typeof text !== 'string') return { signature: [], shingles: 0, bands: 0 };

  let normalized = text.toLowerCase().replace(/\s+/g, ' ').trim();
  let shingles = new Set();
  for (let i = 0; i <= normalized.length - shingleSize; i++) {
    shingles.add(normalized.substring(i, i + shingleSize));
  }

  let shingleArr = Array.from(shingles);
  let signature = [];
  for (let h = 0; h < numHashes; h++) {
    let minHash = Infinity;
    let a = (h * 1103515245 + 12345) >>> 0;
    let b = ((h + 1) * 1103515245 + 12345) >>> 0;
    for (let s = 0; s < shingleArr.length; s++) {
      let charSum = 0;
      for (let c = 0; c < shingleArr[s].length; c++) {
        charSum += shingleArr[s].charCodeAt(c);
      }
      let hash = ((a * charSum + b) & 0x7FFFFFFF) % 104729;
      if (hash < minHash) minHash = hash;
    }
    signature.push(minHash === Infinity ? 0 : minHash);
  }

  let numBands = options.bands || Math.floor(numHashes / 4);
  let rowsPerBand = Math.floor(numHashes / numBands);
  let bands = [];
  for (let i = 0; i < numBands; i++) {
    let band = signature.slice(i * rowsPerBand, (i + 1) * rowsPerBand);
    let bandHash = 0;
    for (let j = 0; j < band.length; j++) bandHash = ((bandHash * 31) + band[j]) & 0x7FFFFFFF;
    bands.push(bandHash);
  }

  return { signature: signature, shingles: shingleArr.length, bands: bands, numHashes: numHashes };
}

function estimateSimilarity(sigA, sigB) {
  if (!sigA.length || !sigB.length || sigA.length !== sigB.length) return 0;
  let matches = 0;
  for (let i = 0; i < sigA.length; i++) {
    if (sigA[i] === sigB[i]) matches++;
  }
  return matches / sigA.length;
}

