function generateWhisperResponse(transcript: string, options = {}: Record<string, any>) {
  options = options || {};
  const confidence = options.confidence || 0;
  const language = options.language || 'en';
  const segments = options.segments || [];

  if (!transcript || typeof transcript !== 'string') {
    return { text: '', confidence: 0, tokens: 0, status: 'empty' };
  }

  const text = transcript.trim();
  const tokens = text.split(/\s+/).length;
  const sentences = text.split(/[.!?]+/).filter(function(s) { return s.trim().length > 0; });

  let quality = 'low';
  if (confidence >= 0.9 && tokens >= 3) quality = 'high';
  else if (confidence >= 0.7 && tokens >= 2) quality = 'medium';

  const timestamps = [];
  for (let i = 0; i < segments.length; i++) {
    timestamps.push({
      text: segments[i].text || '',
      start: segments[i].start || 0,
      end: segments[i].end || 0,
      confidence: segments[i].confidence || confidence
    });
  }

  return {
    text: text,
    confidence: confidence,
    tokens: tokens,
    sentences: sentences.length,
    language: language,
    quality: quality,
    timestamps: timestamps,
    status: 'ok',
    needsReview: confidence < 0.7 || tokens < 3
  };
}

