function remembranceScore(pattern: any) {
  if (!pattern || !pattern.code) return { total: 0, dimensions: {}, pass: false };

  const weights = { relevance: 0.25, coherency: 0.25, usage: 0.20, freshness: 0.15, trust: 0.15 };

  const relevance = Math.min(1, Math.max(0, pattern.relevance || 0));
  const coherency = Math.min(1, Math.max(0, pattern.coherency || 0));

  const uses = pattern.uses || 0;
  const successes = pattern.successes || 0;
  const usage = uses > 0 ? (successes / uses) * Math.min(1, Math.log2(uses + 1) / 5) : 0;

  const daysSinceUse = pattern.daysSinceUse || 0;
  const freshness = daysSinceUse <= 7 ? 1.0 : daysSinceUse <= 30 ? 0.8 : daysSinceUse <= 90 ? 0.5 : daysSinceUse <= 180 ? 0.3 : 0.1;

  const hasTest = pattern.hasTest ? 1 : 0;
  const validated = pattern.validated ? 0.5 : 0;
  const community = Math.min(1, (pattern.votes || 0) / 10);
  const trust = (hasTest * 0.4) + (validated * 0.3) + (community * 0.3);

  let total = (relevance * weights.relevance) + (coherency * weights.coherency) +
              (usage * weights.usage) + (freshness * weights.freshness) + (trust * weights.trust);

  total = Math.round(total * 1000) / 1000;

  return {
    total: total,
    dimensions: { relevance: relevance, coherency: coherency, usage: Math.round(usage * 1000) / 1000, freshness: freshness, trust: Math.round(trust * 1000) / 1000 },
    pass: total >= 0.6,
    weights: weights
  };
}

