  let relevance = Math.min(1, Math.max(0, pattern.relevance || 0));
  let coherency = Math.min(1, Math.max(0, pattern.coherency || 0));

  let uses = pattern.uses || 0;
  let successes = pattern.successes || 0;
  let usage = uses > 0 ? (successes / uses) * Math.min(1, Math.log2(uses + 1) / 5) : 0;

  let daysSinceUse = pattern.daysSinceUse || 0;
  let freshness = daysSinceUse <= 7 ? 1.0 : daysSinceUse <= 30 ? 0.8 : daysSinceUse <= 90 ? 0.5 : daysSinceUse <= 180 ? 0.3 : 0.1;

  let hasTest = pattern.hasTest ? 1 : 0;
  let validated = pattern.validated ? 0.5 : 0;
  let community = Math.min(1, (pattern.votes || 0) / 10);
  let trust = (hasTest * 0.4) + (validated * 0.3) + (community * 0.3);

  let total = (relevance * weights.relevance) + (coherency * weights.coherency) +
              (usage * weights.usage) + (freshness * weights.freshness) + (trust * weights.trust);

  total = Math.round(total * 1000) / 1000;

  return {
    total: total,
    dimensions: { relevance: relevance, coherency: coherency, usage: Math.round(usage * 1000) / 1000, freshness: freshness, trust: Math.round(trust * 1000) / 1000 },
    pass: total >= 0.6,
    weights: weights
  };
}

