function CoherenceRating(score: any, dimensions: any[]) {
  let dims = dimensions || {};
  let total = typeof score === 'number' ? score : 0;
  let level = total >= 0.8 ? 'high' : total >= 0.6 ? 'medium' : 'low';
  let bar = function(val) {
    let filled = Math.round(val * 20);
    let empty = 20 - filled;
    let result = '';
    for (let i = 0; i < filled; i++) result += '#';
    for (let i = 0; i < empty; i++) result += '-';
    return '[' + result + '] ' + (val * 100).toFixed(1) + '%';
  };
  let output = {
    total: total,
    level: level,
    bar: bar(total),
    dimensions: {}
  };
  let keys = Object.keys(dims);
  for (let i = 0; i < keys.length; i++) {
    output.dimensions[keys[i]] = {
      score: dims[keys[i]],
      bar: bar(dims[keys[i]])
    };
  }
  output.passes = total >= 0.6;
  return output;
}

