patterns.code:
'use strict';

/**
 * Structured Description Layer — replaces freeform text descriptions
 * with a lightweight schema: inputs → transform → outputs, with constraint tags.
 *
 * This improves cross-domain matching by allowing structural comparison
 * rather than relying solely on text similarity.
 *
 * A structured description looks like:
 * {
 *   inputs: ['array<number>'],
 *   transform: 'sort-ascending',
 *   outputs: ['array<number>'],
 *   constraints: ['stable', 'in-place'],
 *   domain: 'algorithm',
 *   freeform: 'Sorts an array of numbers in ascending order'
 * }
 */

/**
 * Parse a freeform description into a structured description object.
 * Uses heuristic extraction of inputs, outputs, transforms, and constraints.
 * @param {string} description - Freeform text description
 * @param {object} [context] - Optional context (code, tags, language)
 * @returns {object} Structured description
 */
function parseStructuredDescription(description, context = {}) {
  if (!description || typeof description !== 'string') {
    return createEmptyStructured(description);
  }

  const lower = description.toLowerCase();
  const inputs = extractInputs(lower, context);
  const outputs = extractOutputs(lower, context);
  const transform = extractTransform(lower);
  const constraints = extractConstraints(lower);
  const domain = inferDomain(lower, context.tags || []);

  return {
    inputs,
    transform,
    outputs,
    constraints,
    domain,
    freeform: description,
  };
}

/**
 * Create an empty structured description as a fallback.
 */
function createEmptyStructured(freeform) {
  return {
    inputs: [],
    transform: '',
    outputs: [],
    constraints: [],
    domain: 'general',
    freeform: freeform || '',
  };
}

/**
 * Validate that a structured description object has the correct shape.
 * @param {object} desc - Structured description to validate
 * @returns {{ valid: boolean, errors: string[] }}
 */
function validateStructuredDescription(desc) {
  const errors = [];
  if (!desc || typeof desc !== 'object') {
    return { valid: false, errors: ['Description must be an object'] };
  }
  if (!Array.isArray(desc.inputs)) errors.push('inputs must be an array');
  if (typeof desc.transform !== 'string') errors.push('transform must be a string');
  if (!Array.isArray(desc.outputs)) errors.push('outputs must be an array');
  if (!Array.isArray(desc.constraints)) errors.push('constraints must be an array');
  if (typeof desc.domain !== 'string') errors.push('domain must be a string');

  return { valid: errors.length === 0, errors };
}

/**
 * Compute structural similarity between two structured descriptions.
 * Returns 0-1 where 1 is structurally identical.
 * @param {object} a - First structured description
 * @param {object} b - Second structured description
 * @returns {number} Similarity score 0-1
 */
function structuralSimilarity(a, b) {
  if (!a || !b) return 0;

  const inputSim = setOverlap(a.inputs || [], b.inputs || []);
  const outputSim = setOverlap(a.outputs || [], b.outputs || []);
  const transformSim = tokenSimilarity(a.transform || '', b.transform || '');
  const constraintSim = setOverlap(a.constraints || [], b.constraints || []);
  const domainMatch = (a.domain || '') === (b.domain || '') ? 1.0 : 0.0;

  // Weighted composite — transform and I/O matter most
  return (
    inputSim * 0.25 +
    outputSim * 0.25 +
    transformSim * 0.30 +
    constraintSim * 0.10 +
    domainMatch * 0.10
  );
}

// ─── Internal Extraction Helpers ─────────────────────────────────────────

const INPUT_PATTERNS = [
  /(?:takes?|accepts?|receives?|given|from)\s+(?:an?\s+)?(\w[\w<>,\s]*)/g,
  /input[s]?[:\s]+(\w[\w<>,\s]*)/g,
  /\((\w+(?:\s*,\s*\w+)*)\)\s*(?:=>|->)/g,
];

const OUTPUT_PATTERNS = [
  /(?:returns?|produces?|outputs?|yields?|gives?)\s+(?:an?\s+)?(\w[\w<>,\s]*)/g,
  /output[s]?[:\s]+(\w[\w<>,\s]*)/g,
  /(?:=>|->)\s+(\w[\w<>,\s]*)/g,
];

const TRANSFORM_KEYWORDS = [
  'sort', 'filter', 'map', 'reduce', 'merge', 'split', 'join', 'parse',
  'format', 'convert', 'transform', 'validate', 'sanitize', 'encode', 'decode',
  'hash', 'encrypt', 'decrypt', 'compress', 'decompress', 'serialize', 'deserialize',
  'debounce', 'throttle', 'cache', 'memoize', 'retry', 'batch', 'chunk',
  'flatten', 'group', 'aggregate', 'normalize', 'denormalize',
  'search', 'find', 'match', 'replace', 'extract', 'traverse', 'iterate',
  'create', 'build', 'compose', 'wrap', 'unwrap', 'bind',
];

const CONSTRAINT_KEYWORDS = [
  'stable', 'in-place', 'immutable', 'pure', 'async', 'sync', 'recursive',
  'iterative', 'lazy', 'eager', 'thread-safe', 'concurrent', 'idempotent',
  'deterministic', 'ordered', 'unordered', 'unique', 'sorted',
  'case-insensitive', 'case-sensitive', 'null-safe', 'type-safe',
  'constant-time', 'linear-time', 'logarithmic', 'quadratic',
];

const DOMAIN_MAP = {
  'algorithm': ['sort', 'search', 'traverse', 'graph', 'tree', 'path', 'dynamic programming', 'recursion', 'binary'],
  'data-structure': ['array', 'list', 'map', 'set', 'queue', 'stack', 'tree', 'graph', 'heap', 'trie'],
  'string-processing': ['string', 'text', 'regex', 'parse', 'format', 'template', 'encode', 'decode'],
  'io': ['file', 'read', 'write', 'stream', 'buffer', 'pipe', 'stdin', 'stdout'],
  'network': ['http', 'request', 'fetch', 'api', 'url', 'socket', 'websocket'],
  'security': ['encrypt', 'decrypt', 'hash', 'auth', 'token', 'csrf', 'sanitize', 'escape'],
  'async': ['async', 'await', 'promise', 'callback', 'event', 'observable', 'debounce', 'throttle'],
  'validation': ['validate', 'check', 'assert', 'verify', 'schema', 'constraint'],
  'utility': ['helper', 'util', 'tool', 'convert', 'transform', 'wrap'],
};

function extractInputs(text, context) {
  const found = new Set();
  for (const pattern of INPUT_PATTERNS) {
    pattern.lastIndex = 0;
    let match;
    while ((match = pattern.exec(text)) !== null) {
      const tokens = match[1].split(/[,\s]+/).filter(t => t.length > 1);
      tokens.forEach(t => found.add(normalizeType(t)));
    }
  }

  // Also extract from code parameter names if available
  if (context.code) {
    const paramMatch = context.code.match(/function\s+\w+\s*\(([^)]*)\)/);
    if (paramMatch && paramMatch[1]) {
      paramMatch[1].split(',').forEach(p => {
        const name = p.trim().split(/[=:]/).shift().trim();
        if (name && name.length > 1) found.add(normalizeType(name));
      });
    }
  }

  return [...found];
}

function extractOutputs(text, context) {
  const found = new Set();
  for (const pattern of OUTPUT_PATTERNS) {
    pattern.lastIndex = 0;
    let match;
    while ((match = pattern.exec(text)) !== null) {
      const tokens = match[1].split(/[,\s]+/).filter(t => t.length > 1);
      tokens.forEach(t => found.add(normalizeType(t)));
    }
  }
  return [...found];
}

function extractTransform(text) {
  const found = [];
  for (const kw of TRANSFORM_KEYWORDS) {
    if (text.includes(kw)) found.push(kw);
  }
  return found.join('-') || 'transform';
}

function extractConstraints(text) {
  const found = [];
  for (const c of CONSTRAINT_KEYWORDS) {
    // For multi-word constraints, check directly
    if (c.includes('-')) {
      if (text.includes(c.replace(/-/g, ' ')) || text.includes(c)) found.push(c);
    } else {
      // Word-boundary match for single words
      const re = new RegExp('\\b' + c + '\\b');
      if (re.test(text)) found.push(c);
    }
  }
  return found;
}

function inferDomain(text, tags) {
  const combined = text + ' ' + tags.join(' ');
  let bestDomain = 'general';
  let bestScore = 0;

  for (const [domain, keywords] of Object.entries(DOMAIN_MAP)) {
    let score = 0;
    for (const kw of keywords) {
      if (combined.includes(kw)) score++;
    }
    if (score > bestScore) {
      bestScore = score;
      bestDomain = domain;
    }
  }

  return bestDomain;
}

function normalizeType(raw) {
  return raw.toLowerCase().replace(/[^a-z0-9<>,]/g, '').trim();
}

function setOverlap(a, b) {
  if (a.length === 0 && b.length === 0) return 1.0; // Both empty — perfect match
  if (a.length === 0 || b.length === 0) return 0.0;
  const setA = new Set(a.map(x => String(x).toLowerCase()));
  const setB = new Set(b.map(x => String(x).toLowerCase()));
  let intersection = 0;
  for (const item of setA) {
    if (setB.has(item)) intersection++;
  }
  const union = new Set([...setA, ...setB]).size;
  return union > 0 ? intersection / union : 0;
}

function tokenSimilarity(a, b) {
  if (!a && !b) return 0.0;
  if (a === b) return 1.0;
  if (!a || !b) return 0.0;
  const tokensA = new Set(a.split(/[-_\s]+/).filter(Boolean));
  const tokensB = new Set(b.split(/[-_\s]+/).filter(Boolean));
  if (tokensA.size === 0 && tokensB.size === 0) return 0.0;
  return setOverlap([...tokensA], [...tokensB]);
}

module.exports = {
  parseStructuredDescription,
  validateStructuredDescription,
  structuralSimilarity,
  createEmptyStructured,
  extractInputs,
  extractOutputs,
  extractTransform,
  extractConstraints,
  inferDomain,
  setOverlap,
  tokenSimilarity,
  DOMAIN_MAP,
  TRANSFORM_KEYWORDS,
  CONSTRAINT_KEYWORDS,
};

patterns.testCode:
'use strict';

const { describe, it } = require('node:test');
const assert = require('assert');

const {
  parseStructuredDescription,
  validateStructuredDescription,
  structuralSimilarity,
  createEmptyStructured,
  extractTransform,
  extractConstraints,
  inferDomain,
  setOverlap,
  tokenSimilarity,
} = require('../src/core/structured-description');

describe('Structured Description Layer', () => {
  describe('parseStructuredDescription', () => {
    it('parses a sorting description', () => {
      const result = parseStructuredDescription('takes an array and returns a sorted array');
      assert.ok(result.inputs.length > 0, 'should extract inputs');
      assert.ok(result.outputs.length > 0, 'should extract outputs');
      assert.strictEqual(result.freeform, 'takes an array and returns a sorted array');
      assert.ok(result.domain, 'should have a domain');
    });

    it('handles empty/null descriptions', () => {
      const empty = parseStructuredDescription('');
      assert.deepStrictEqual(empty.inputs, []);
      assert.strictEqual(empty.transform, '');
      assert.deepStrictEqual(empty.outputs, []);

      const nullResult = parseStructuredDescription(null);
      assert.deepStrictEqual(nullResult.inputs, []);
    });

    it('extracts transform keywords', () => {
      const result = parseStructuredDescription('filter and sort the items then merge results');
      assert.ok(result.transform.includes('filter'), 'should find filter');
      assert.ok(result.transform.includes('sort'), 'should find sort');
      assert.ok(result.transform.includes('merge'), 'should find merge');
    });

    it('extracts constraints', () => {
      const result = parseStructuredDescription('a pure, immutable sort that is thread-safe');
      assert.ok(result.constraints.includes('pure'));
      assert.ok(result.constraints.includes('immutable'));
      assert.ok(result.constraints.includes('thread-safe'));
    });

    it('infers domain from description text', () => {
      const algo = parseStructuredDescription('binary search through a sorted tree');
      assert.strictEqual(algo.domain, 'algorithm');

      const security = parseStructuredDescription('encrypt and hash the auth token');
      assert.strictEqual(security.domain, 'security');
    });

    it('uses code context for input extraction', () => {
      const result = parseStructuredDescription('adds two numbers', {
        code: 'function add(left, right) { return left + right; }',
      });
      assert.ok(result.inputs.length >= 1, 'should extract params from code');
      assert.ok(result.inputs.some(i => i === 'left' || i === 'right'), 'should find param names');
    });
  });

  describe('validateStructuredDescription', () => {
    it('accepts a valid structured description', () => {
      const valid = {
        inputs: ['number'],
        transform: 'sort',
        outputs: ['array'],
        constraints: ['stable'],
        domain: 'algorithm',
      };
      const result = validateStructuredDescription(valid);
      assert.strictEqual(result.valid, true);
      assert.strictEqual(result.errors.length, 0);
    });

    it('rejects null/undefined', () => {
      const result = validateStructuredDescription(null);
      assert.strictEqual(result.valid, false);
    });

    it('reports missing fields', () => {
      const result = validateStructuredDescription({ inputs: 'not-array' });
      assert.strictEqual(result.valid, false);
      assert.ok(result.errors.length > 0);
    });
  });

  describe('structuralSimilarity', () => {
    it('returns 1.0 for identical structures', () => {
      const desc = {
        inputs: ['array'],
        transform: 'sort',
        outputs: ['array'],
        constraints: ['stable'],
        domain: 'algorithm',
      };
      assert.strictEqual(structuralSimilarity(desc, desc), 1.0);
    });

    it('returns 0 for completely different structures', () => {
      const a = {
        inputs: ['string'],
        transform: 'encrypt',
        outputs: ['buffer'],
        constraints: ['async'],
        domain: 'security',
      };
      const b = {
        inputs: ['number'],
        transform: 'sort',
        outputs: ['array'],
        constraints: ['stable'],
        domain: 'algorithm',
      };
      const sim = structuralSimilarity(a, b);
      assert.ok(sim < 0.3, `Expected low similarity, got ${sim}`);
    });

    it('returns moderate similarity for partially matching structures', () => {
      const a = {
        inputs: ['array'],
        transform: 'sort-filter',
        outputs: ['array'],
        constraints: ['stable'],
        domain: 'algorithm',
      };
      const b = {
        inputs: ['array'],
        transform: 'sort-merge',
        outputs: ['array'],
        constraints: ['in-place'],
        domain: 'algorithm',
      };
      const sim = structuralSimilarity(a, b);
      assert.ok(sim > 0.4, `Expected moderate similarity, got ${sim}`);
      assert.ok(sim < 1.0, `Expected less than perfect, got ${sim}`);
    });

    it('handles null/undefined gracefully', () => {
      assert.strictEqual(structuralSimilarity(null, null), 0);
      assert.strictEqual(structuralSimilarity({}, null), 0);
    });
  });

  describe('createEmptyStructured', () => {
    it('creates a valid empty structure', () => {
      const empty = createEmptyStructured('some text');
      assert.deepStrictEqual(empty.inputs, []);
      assert.strictEqual(empty.transform, '');
      assert.deepStrictEqual(empty.outputs, []);
      assert.deepStrictEqual(empty.constraints, []);
      assert.strictEqual(empty.domain, 'general');
      assert.strictEqual(empty.freeform, 'some text');
    });
  });

  describe('setOverlap', () => {
    it('returns 1.0 for identical sets', () => {
      assert.strictEqual(setOverlap(['a', 'b'], ['a', 'b']), 1.0);
    });

    it('returns 0.0 for disjoint sets', () => {
      assert.strictEqual(setOverlap(['a'], ['b']), 0.0);
    });

    it('returns 1.0 for two empty sets', () => {
      assert.strictEqual(setOverlap([], []), 1.0);
    });

    it('returns 0.0 when one set is empty', () => {
      assert.strictEqual(setOverlap(['a'], []), 0.0);
    });

    it('computes Jaccard correctly', () => {
      const overlap = setOverlap(['a', 'b', 'c'], ['b', 'c', 'd']);
      assert.ok(Math.abs(overlap - 0.5) < 0.01, `Expected ~0.5, got ${overlap}`);
    });
  });

  describe('tokenSimilarity', () => {
    it('returns 1.0 for identical strings', () => {
      assert.strictEqual(tokenSimilarity('sort-filter', 'sort-filter'), 1.0);
    });

    it('returns 0.0 for empty strings', () => {
      assert.strictEqual(tokenSimilarity('', ''), 0.0);
    });

    it('finds partial matches', () => {
      const sim = tokenSimilarity('sort-filter', 'sort-merge');
      assert.ok(sim > 0.2 && sim < 0.8, `Expected partial match, got ${sim}`);
    });
  });

  describe('inferDomain', () => {
    it('detects algorithm domain', () => {
      assert.strictEqual(inferDomain('sort and search through binary tree', []), 'algorithm');
    });

    it('detects network domain', () => {
      assert.strictEqual(inferDomain('http fetch api request', []), 'network');
    });

    it('defaults to general for unknown text', () => {
      assert.strictEqual(inferDomain('something completely unrelated xyzzy', []), 'general');
    });

    it('uses tags as additional signal', () => {
      const domain = inferDomain('process data', ['encryption', 'hash', 'auth']);
      assert.strictEqual(domain, 'security');
    });
  });

  describe('integration with pattern library', () => {
    it('parseStructuredDescription result passes validation', () => {
      const parsed = parseStructuredDescription('takes a list and returns sorted unique items');
      const validation = validateStructuredDescription(parsed);
      assert.strictEqual(validation.valid, true, `Errors: ${validation.errors.join(', ')}`);
    });

    it('cross-domain matching finds structural isomorphisms', () => {
      // Same structural pattern, different domains
      const sortDesc = parseStructuredDescription('takes an array and returns a sorted array');
      const filterDesc = parseStructuredDescription('takes an array and returns a filtered array');
      const encryptDesc = parseStructuredDescription('takes a string and returns encrypted buffer');

      const sortFilterSim = structuralSimilarity(sortDesc, filterDesc);
      const sortEncryptSim = structuralSimilarity(sortDesc, encryptDesc);

      // sort and filter should be more structurally similar than sort and encrypt
      assert.ok(sortFilterSim > sortEncryptSim,
        `sort-filter similarity (${sortFilterSim}) should exceed sort-encrypt (${sortEncryptSim})`);
    });
  });
});

patterns.code:
'use strict';

/**
 * Pattern Lifecycle State Machine — Centralizes all pattern state transitions.
 *
 * States:
 *   CANDIDATE  → Unproven code awaiting test proof
 *   PATTERN    → Proven, active, searchable code
 *   RETIRED    → Archived due to low usage/coherency
 *
 * Transitions:
 *   CANDIDATE → PATTERN   (promote: test proof + coherency gate)
 *   PATTERN   → RETIRED   (retire: composite score below threshold)
 *   PATTERN   → PATTERN   (evolve: new version replaces old)
 *   RETIRED   → CANDIDATE (resurrect: re-enter via healing)
 *
 * Each transition runs hooks:
 *   - guard:  validates preconditions (returns boolean)
 *   - before: runs before the transition (update embeddings, etc.)
 *   - after:  runs after the transition (audit log, family counts, etc.)
 *
 * Usage:
 *   const sm = createPatternLifecycle(store, options);
 *   sm.promote(candidateId, testCode);    // CANDIDATE → PATTERN
 *   sm.retire(patternId);                 // PATTERN → RETIRED
 *   sm.evolve(patternId, newCode, meta);  // PATTERN → PATTERN (new version)
 *   sm.resurrect(archivedId);             // RETIRED → CANDIDATE
 */

const STATES = {
  CANDIDATE: 'candidate',
  PATTERN: 'pattern',
  RETIRED: 'retired',
};

const TRANSITIONS = {
  PROMOTE: 'promote',
  RETIRE: 'retire',
  EVOLVE: 'evolve',
  RESURRECT: 'resurrect',
};

// Valid state transitions: from → [allowed events]
const TRANSITION_MAP = {
  [STATES.CANDIDATE]: {
    [TRANSITIONS.PROMOTE]: STATES.PATTERN,
  },
  [STATES.PATTERN]: {
    [TRANSITIONS.RETIRE]: STATES.RETIRED,
    [TRANSITIONS.EVOLVE]: STATES.PATTERN,
  },
  [STATES.RETIRED]: {
    [TRANSITIONS.RESURRECT]: STATES.CANDIDATE,
  },
};

/**
 * Create a pattern lifecycle state machine bound to a store.
 *
 * @param {object} store - SQLiteStore instance
 * @param {object} [options]
 * @param {number} [options.minPromotionCoherency=0.6] - Min coherency for promotion
 * @param {number} [options.retireThreshold=0.30] - Composite score below which patterns retire
 * @param {Function} [options.onTransition] - Hook called on every transition: (event) => void
 * @returns {object} Lifecycle API
 */
function createPatternLifecycle(store, options = {}) {
  const {
    minPromotionCoherency = 0.6,
    retireThreshold = 0.30,
    onTransition = null,
  } = options;

  const listeners = [];

  function _emit(event) {
    if (onTransition) {
      try { onTransition(event); } catch (_) { /* never break caller */ }
    }
    for (const listener of listeners) {
      try { listener(event); } catch (_) { /* never break caller */ }
    }
  }

  /**
   * Determine the current state of an entity by its ID.
   * Checks patterns table, candidates table, and archive.
   */
  function getState(id) {
    if (!store || !store.db) return null;

    // Check patterns table first (most common lookup)
    const pattern = store.db.prepare('SELECT id FROM patterns WHERE id = ?').get(id);
    if (pattern) return STATES.PATTERN;

    // Check candidates table (unpromoted)
    const candidate = store.db.prepare(
      'SELECT id, promoted_at FROM candidates WHERE id = ?'
    ).get(id);
    if (candidate) {
      return candidate.promoted_at ? STATES.PATTERN : STATES.CANDIDATE;
    }

    // Check archive
    const archived = store.db.prepare('SELECT id FROM pattern_archive WHERE id = ?').get(id);
    if (archived) return STATES.RETIRED;

    return null;
  }

  /**
   * Validate that a transition is allowed.
   */
  function _validateTransition(id, fromState, transition) {
    if (!fromState) {
      return { valid: false, reason: `Entity ${id} not found in any table` };
    }
    const allowed = TRANSITION_MAP[fromState];
    if (!allowed || !allowed[transition]) {
      return {
        valid: false,
        reason: `Transition "${transition}" not allowed from state "${fromState}"`,
      };
    }
    return { valid: true, toState: allowed[transition] };
  }

  // ─── PROMOTE: CANDIDATE → PATTERN ───

  /**
   * Promote a candidate to a proven pattern.
   *
   * Guards:
   *   - Candidate must exist and not already be promoted
   *   - Must have test code (passed in or existing)
   *   - Coherency must meet minimum threshold
   *
   * Hooks:
   *   - After: audit log, update embeddings, update family counts
   *
   * @param {string} candidateId
   * @param {string} [testCode] - Test proof (uses candidate's if not provided)
   * @param {object} [registerFn] - Optional function to register through full oracle pipeline
   * @returns {{ success: boolean, reason?: string, pattern?: object }}
   */
  function promote(candidateId, testCode, registerFn) {
    const currentState = getState(candidateId);
    const validation = _validateTransition(candidateId, currentState, TRANSITIONS.PROMOTE);
    if (!validation.valid) {
      return { success: false, reason: validation.reason };
    }

    // Fetch candidate
    const candidate = store.getCandidate(candidateId);
    if (!candidate) {
      return { success: false, reason: 'Candidate not found' };
    }

    const effectiveTestCode = testCode || candidate.testCode;
    if (!effectiveTestCode) {
      return { success: false, reason: 'No test code provided — test proof required for promotion' };
    }

    if ((candidate.coherencyTotal || 0) < minPromotionCoherency) {
      return {
        success: false,
        reason: `Coherency ${candidate.coherencyTotal} below minimum ${minPromotionCoherency}`,
      };
    }

    // Perform the transition
    let registeredPattern = null;
    if (typeof registerFn === 'function') {
      const result = registerFn({
        name: candidate.name,
        code: candidate.code,
        language: candidate.language,
        description: candidate.description,
        tags: (candidate.tags || []).filter(t => t !== 'candidate'),
        testCode: effectiveTestCode,
      });
      if (!result || !result.registered) {
        return { success: false, reason: result?.reason || 'Registration through oracle pipeline failed' };
      }
      registeredPattern = result.pattern;
    }

    // Mark candidate as promoted
    store.promoteCandidate(candidateId);

    const event = {
      transition: TRANSITIONS.PROMOTE,
      from: STATES.CANDIDATE,
      to: STATES.PATTERN,
      entityId: candidateId,
      patternId: registeredPattern?.id || candidateId,
      name: candidate.name,
      timestamp: new Date().toISOString(),
    };
    _emit(event);

    return { success: true, pattern: registeredPattern, event };
  }

  // ─── RETIRE: PATTERN → RETIRED ───

  /**
   * Retire a single pattern by ID.
   *
   * Guards:
   *   - Pattern must exist in patterns table
   *   - Composite score must be below threshold (or force=true)
   *
   * Hooks:
   *   - Before: archive pattern
   *   - After: cleanup fractal data, audit log
   *
   * @param {string} patternId
   * @param {object} [opts]
   * @param {boolean} [opts.force=false] - Skip composite score check
   * @returns {{ success: boolean, reason?: string }}
   */
  function retire(patternId, opts = {}) {
    const { force = false } = opts;
    const currentState = getState(patternId);
    const validation = _validateTransition(patternId, currentState, TRANSITIONS.RETIRE);
    if (!validation.valid) {
      return { success: false, reason: validation.reason };
    }

    const row = store.db.prepare('SELECT * FROM patterns WHERE id = ?').get(patternId);
    if (!row) {
      return { success: false, reason: 'Pattern not found in patterns table' };
    }

    // Guard: composite score check
    if (!force) {
      const coherency = row.coherency_total || 0;
      const reliability = row.usage_count > 0 ? row.success_count / row.usage_count : 0.5;
      const composite = coherency * 0.6 + reliability * 0.4;
      if (composite >= retireThreshold) {
        return {
          success: false,
          reason: `Composite score ${composite.toFixed(3)} >= threshold ${retireThreshold} — pattern is healthy`,
        };
      }
    }

    // Perform the transition
    store.db.exec('BEGIN IMMEDIATE');
    try {
      store._archivePattern(row, 'retirement');
      if (store._cleanupFractalData) store._cleanupFractalData(patternId);
      store.db.prepare('DELETE FROM patterns WHERE id = ?').run(patternId);
      store._audit('retire', 'patterns', patternId, { name: row.name });
      store.db.exec('COMMIT');
    } catch (e) {
      try { store.db.exec('ROLLBACK'); } catch (_) {}
      return { success: false, reason: `Retirement failed: ${e.message}` };
    }

    const event = {
      transition: TRANSITIONS.RETIRE,
      from: STATES.PATTERN,
      to: STATES.RETIRED,
      entityId: patternId,
      name: row.name,
      timestamp: new Date().toISOString(),
    };
    _emit(event);

    return { success: true, event };
  }

  /**
   * Bulk retire patterns below the composite score threshold.
   * Delegates to the existing store method but emits events for each.
   *
   * @param {number} [minScore] - Override retire threshold
   * @returns {{ retired: number, remaining: number, events: object[] }}
   */
  function retireBulk(minScore) {
    const threshold = minScore ?? retireThreshold;
    const rows = store.db.prepare('SELECT * FROM patterns').all();
    const toRetire = [];

    for (const row of rows) {
      const coherency = row.coherency_total || 0;
      const reliability = row.usage_count > 0 ? row.success_count / row.usage_count : 0.5;
      const composite = coherency * 0.6 + reliability * 0.4;
      if (composite < threshold) {
        toRetire.push(row);
      }
    }

    const events = [];
    store.db.exec('BEGIN IMMEDIATE');
    try {
      for (const row of toRetire) {
        store._archivePattern(row, 'retirement');
        if (store._cleanupFractalData) store._cleanupFractalData(row.id);
        store.db.prepare('DELETE FROM patterns WHERE id = ?').run(row.id);
        store._audit('retire', 'patterns', row.id, { name: row.name });
        events.push({
          transition: TRANSITIONS.RETIRE,
          from: STATES.PATTERN,
          to: STATES.RETIRED,
          entityId: row.id,
          name: row.name,
          timestamp: new Date().toISOString(),
        });
      }
      store.db.exec('COMMIT');
    } catch (e) {
      try { store.db.exec('ROLLBACK'); } catch (_) {}
      return { retired: 0, remaining: rows.length, events: [], error: e.message };
    }

    for (const event of events) _emit(event);

    const remaining = store.db.prepare('SELECT COUNT(*) as c FROM patterns').get().c;
    return { retired: toRetire.length, remaining, events };
  }

  // ─── EVOLVE: PATTERN → PATTERN (new version) ───

  /**
   * Evolve a pattern by updating its code and re-scoring coherency.
   *
   * Guards:
   *   - Pattern must exist
   *
   * Hooks:
   *   - After: update embeddings, append evolution history, audit log
   *
   * @param {string} patternId
   * @param {object} updates - { code, coherencyScore, ... }
   * @returns {{ success: boolean, reason?: string, pattern?: object }}
   */
  function evolve(patternId, updates) {
    const currentState = getState(patternId);
    const validation = _validateTransition(patternId, currentState, TRANSITIONS.EVOLVE);
    if (!validation.valid) {
      return { success: false, reason: validation.reason };
    }

    if (!updates || !updates.code) {
      return { success: false, reason: 'Evolve requires updated code' };
    }

    // Append to evolution history — use direct SQLite access with fallback
    let pattern = null;
    if (typeof store.getPattern === 'function') {
      pattern = store.getPattern(patternId);
    } else if (store.db) {
      const row = store.db.prepare('SELECT * FROM patterns WHERE id = ?').get(patternId);
      if (row) pattern = row;
    }
    let history = pattern?.evolutionHistory || [];
    if (typeof history === 'string') {
      try { history = JSON.parse(history); } catch (_) { history = []; }
    }
    if (!Array.isArray(history)) history = [];
    history.push({
      type: 'evolve',
      timestamp: new Date().toISOString(),
      previousCode: pattern?.code?.substring(0, 200),
    });

    const updatePayload = {
      ...updates,
      evolutionHistory: history,
      updatedAt: new Date().toISOString(),
    };

    const updated = store.updatePattern(patternId, updatePayload);
    if (!updated) {
      return { success: false, reason: 'Pattern update failed' };
    }

    // Re-embed after code change
    try {
      const { integratePatternIncremental } = require('../compression/fractal-library-bridge');
      integratePatternIncremental(updated, store);
    } catch (_) {
      // Non-fatal — embedding update is best-effort
    }

    const event = {
      transition: TRANSITIONS.EVOLVE,
      from: STATES.PATTERN,
      to: STATES.PATTERN,
      entityId: patternId,
      name: updated.name,
      timestamp: new Date().toISOString(),
    };
    _emit(event);

    return { success: true, pattern: updated, event };
  }

  // ─── RESURRECT: RETIRED → CANDIDATE ───

  /**
   * Resurrect an archived pattern back into the candidate pool.
   *
   * Guards:
   *   - Pattern must exist in pattern_archive
   *
   * Hooks:
   *   - After: insert into candidates, audit log
   *
   * @param {string} archivedId
   * @returns {{ success: boolean, reason?: string, candidate?: object }}
   */
  function resurrect(archivedId) {
    const currentState = getState(archivedId);
    const validation = _validateTransition(archivedId, currentState, TRANSITIONS.RESURRECT);
    if (!validation.valid) {
      return { success: false, reason: validation.reason };
    }

    const archived = store.db.prepare('SELECT * FROM pattern_archive WHERE id = ?').get(archivedId);
    if (!archived) {
      return { success: false, reason: 'Archived pattern not found' };
    }

    // Parse full row data for restoration
    let fullRow;
    try {
      fullRow = JSON.parse(archived.full_row_json || '{}');
    } catch (_) {
      fullRow = {};
    }

    const now = new Date().toISOString();
    const candidateId = archived.id;

    // Insert into candidates table as a re-entry
    store.db.exec('BEGIN IMMEDIATE');
    try {
      store.db.prepare(`
        INSERT OR REPLACE INTO candidates
          (id, name, code, language, pattern_type, coherency_total, coherency_json,
           test_code, tags, description, parent_pattern, generation_method, created_at, updated_at)
        VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
      `).run(
        candidateId,
        archived.name,
        archived.code,
        archived.language || 'unknown',
        archived.pattern_type || 'utility',
        archived.coherency_total || 0,
        archived.coherency_json || '{}',
        archived.test_code || fullRow.test_code || null,
        archived.tags || fullRow.tags || '[]',
        fullRow.description || null,
        null, // no parent — this is a resurrection
        'resurrected',
        now,
        now
      );

      // Remove from archive
      store.db.prepare('DELETE FROM pattern_archive WHERE id = ?').run(archivedId);

      store._audit('resurrect', 'pattern_archive', archivedId, {
        name: archived.name,
        previousReason: archived.deleted_reason,
      });

      store.db.exec('COMMIT');
    } catch (e) {
      try { store.db.exec('ROLLBACK'); } catch (_) {}
      return { success: false, reason: `Resurrection failed: ${e.message}` };
    }

    const candidate = store.getCandidate(candidateId);

    const event = {
      transition: TRANSITIONS.RESURRECT,
      from: STATES.RETIRED,
      to: STATES.CANDIDATE,
      entityId: archivedId,
      name: archived.name,
      timestamp: now,
    };
    _emit(event);

    return { success: true, candidate, event };
  }

  // ─── Subscriptions ───

  function subscribe(listener) {
    listeners.push(listener);
    return () => {
      const idx = listeners.indexOf(listener);
      if (idx >= 0) listeners.splice(idx, 1);
    };
  }

  return {
    // State queries
    getState,
    STATES,
    TRANSITIONS,
    TRANSITION_MAP,

    // Transitions
    promote,
    retire,
    retireBulk,
    evolve,
    resurrect,

    // Subscriptions
    subscribe,
  };
}

module.exports = {
  createPatternLifecycle,
  STATES,
  TRANSITIONS,
  TRANSITION_MAP,
};

