/**
 * Sorted Array — array that maintains sort order on insert
 * createSortedArray(compareFn?) → { insert, remove, indexOf, toArray, size }
 */
function createSortedArray(compareFn) {
  const compare = compareFn || ((a, b) => (a < b ? -1 : a > b ? 1 : 0));
  const items = [];

  function binarySearch(value) {
    let lo = 0;
    let hi = items.length;
    while (lo < hi) {
      const mid = (lo + hi) >>> 1;
      if (compare(items[mid], value) < 0) {
        lo = mid + 1;
      } else {
        hi = mid;
      }
    }
    return lo;
  }

  function insert(value) {
    const index = binarySearch(value);
    items.splice(index, 0, value);
  }

  function remove(value) {
    const index = binarySearch(value);
    if (index < items.length && compare(items[index], value) === 0) {
      items.splice(index, 1);
      return true;
    }
    return false;
  }

  function indexOf(value) {
    const index = binarySearch(value);
    if (index < items.length && compare(items[index], value) === 0) {
      return index;
    }
    return -1;
  }

  function toArray() {
    return items.slice();
  }

  function size() {
    return items.length;
  }

  return { insert, remove, indexOf, toArray, size };
}

module.exports = { createSortedArray };

/**
 * Ring Buffer — fixed-size circular buffer
 * createRingBuffer(capacity) → { push, get, toArray, isFull, size }
 */
function createRingBuffer(capacity) {
  const buffer = new Array(capacity);
  let writeIndex = 0;
  let count = 0;

  function push(value) {
    buffer[writeIndex] = value;
    writeIndex = (writeIndex + 1) % capacity;
    if (count < capacity) count++;
  }

  function get(index) {
    if (index < 0 || index >= count) return undefined;
    if (count < capacity) {
      return buffer[index];
    }
    // When full, oldest element is at writeIndex
    const actualIndex = (writeIndex + index) % capacity;
    return buffer[actualIndex];
  }

  function toArray() {
    const result = [];
    for (let i = 0; i < count; i++) {
      result.push(get(i));
    }
    return result;
  }

  function isFull() {
    return count === capacity;
  }

  function size() {
    return count;
  }

  return { push, get, toArray, isFull, size };
}

module.exports = { createRingBuffer };

/**
 * Queue — FIFO data structure
 * createQueue() → { enqueue, dequeue, peek, size, isEmpty }
 */
function createQueue() {
  const items = [];
  let front = 0;

  function enqueue(value) {
    items.push(value);
  }

  function dequeue() {
    if (front >= items.length) return undefined;
    const value = items[front];
    items[front] = undefined; // allow GC
    front++;
    // compact when half the array is empty
    if (front > items.length / 2 && front > 10) {
      items.splice(0, front);
      front = 0;
    }
    return value;
  }

  function peek() {
    if (front >= items.length) return undefined;
    return items[front];
  }

  function size() {
    return items.length - front;
  }

  function isEmpty() {
    return size() === 0;
  }

  return { enqueue, dequeue, peek, size, isEmpty };
}

module.exports = { createQueue };

/**
 * BiMap — bidirectional map (bijection between keys and values)
 * createBiMap() → { set, getByKey, getByValue, deleteByKey, deleteByValue, size }
 */
function createBiMap() {
  const forward = new Map();  // key → value
  const reverse = new Map();  // value → key

  function set(key, value) {
    // Remove existing mappings if they conflict
    if (forward.has(key)) {
      const oldValue = forward.get(key);
      reverse.delete(oldValue);
    }
    if (reverse.has(value)) {
      const oldKey = reverse.get(value);
      forward.delete(oldKey);
    }
    forward.set(key, value);
    reverse.set(value, key);
  }

  function getByKey(key) {
    return forward.get(key);
  }

  function getByValue(value) {
    return reverse.get(value);
  }

  function deleteByKey(key) {
    if (!forward.has(key)) return false;
    const value = forward.get(key);
    forward.delete(key);
    reverse.delete(value);
    return true;
  }

  function deleteByValue(value) {
    if (!reverse.has(value)) return false;
    const key = reverse.get(value);
    reverse.delete(value);
    forward.delete(key);
    return true;
  }

  function size() {
    return forward.size;
  }

  return { set, getByKey, getByValue, deleteByKey, deleteByValue, size };
}

module.exports = { createBiMap };

/**
 * Matrix operations — matrixMultiply, matrixTranspose, matrixAdd
 * Matrices are represented as 2D arrays (array of rows).
 */
function matrixMultiply(a, b) {
  const rowsA = a.length;
  const colsA = a[0].length;
  const colsB = b[0].length;
  if (colsA !== b.length) {
    throw new Error('Incompatible matrix dimensions for multiplication');
  }
  const result = [];
  for (let i = 0; i < rowsA; i++) {
    result[i] = [];
    for (let j = 0; j < colsB; j++) {
      let sum = 0;
      for (let k = 0; k < colsA; k++) {
        sum += a[i][k] * b[k][j];
      }
      result[i][j] = sum;
    }
  }
  return result;
}

function matrixTranspose(matrix) {
  const rows = matrix.length;
  const cols = matrix[0].length;
  const result = [];
  for (let j = 0; j < cols; j++) {
    result[j] = [];
    for (let i = 0; i < rows; i++) {
      result[j][i] = matrix[i][j];
    }
  }
  return result;
}

function matrixAdd(a, b) {
  if (a.length !== b.length || a[0].length !== b[0].length) {
    throw new Error('Matrices must have the same dimensions for addition');
  }
  const result = [];
  for (let i = 0; i < a.length; i++) {
    result[i] = [];
    for (let j = 0; j < a[0].length; j++) {
      result[i][j] = a[i][j] + b[i][j];
    }
  }
  return result;
}

module.exports = { matrixMultiply, matrixTranspose, matrixAdd };

/**
 * combinations - Generate all k-combinations of an array.
 * @param {Array} arr - The input array.
 * @param {number} k - The size of each combination.
 * @returns {Array<Array>} An array of all k-combinations.
 */
function combinations(arr, k) {
  if (k < 0 || k > arr.length) return [];
  if (k === 0) return [[]];
  if (k === arr.length) return [arr.slice()];

  const result = [];

  function backtrack(start, current) {
    if (current.length === k) {
      result.push(current.slice());
      return;
    }

    for (let i = start; i < arr.length; i++) {
      current.push(arr[i]);
      backtrack(i + 1, current);
      current.pop();
    }
  }

  backtrack(0, []);
  return result;
}

module.exports = combinations;

/**
 * wrapText - Wraps text to a specified width by inserting newlines between words.
 * @param {string} str - The text to wrap.
 * @param {number} width - The maximum line width.
 * @returns {string} The wrapped text with newline characters.
 */
function wrapText(str, width) {
  if (typeof str !== 'string') return '';
  if (width <= 0) return str;
  const words = str.split(/\s+/).filter(Boolean);
  if (words.length === 0) return '';
  const lines = [];
  let currentLine = words[0];
  for (let i = 1; i < words.length; i++) {
    if (currentLine.length + 1 + words[i].length <= width) {
      currentLine += ' ' + words[i];
    } else {
      lines.push(currentLine);
      currentLine = words[i];
    }
  }
  lines.push(currentLine);
  return lines.join('\n');
}

module.exports = wrapText;

/**
 * Observable — reactive value with subscriptions
 * createObservable(initialValue) → { get, set, subscribe, unsubscribe }
 */
function createObservable(initialValue) {
  let value = initialValue;
  const listeners = new Map();
  let nextId = 0;

  function get() {
    return value;
  }

  function set(newValue) {
    const oldValue = value;
    value = newValue;
    for (const [, listener] of listeners) {
      listener(newValue, oldValue);
    }
  }

  function subscribe(listener) {
    const id = nextId++;
    listeners.set(id, listener);
    return id;
  }

  function unsubscribe(id) {
    return listeners.delete(id);
  }

  return { get, set, subscribe, unsubscribe };
}

module.exports = { createObservable };

function parseQueryString(qs: any) {
  if (!qs || qs === '?') return {};
  return qs.replace(/^\?/, '').split('&').reduce(function(obj, pair) {
    let parts = pair.split('=');
    obj[decodeURIComponent(parts[0])] = decodeURIComponent(parts[1] || '');
    return obj;
  }, {});
}

