      setHeader() {},
      writeHead(code) { if (code === 429) rateLimited = true; },
      end() {},
    };
    limiter(makeReq(), res2, () => {});
    assert.ok(rateLimited, 'should rate limit by real socket IP, ignoring spoofed header');
  });
});

