import "sync"

func Memoize[K comparable, V any](fn func(K) V) func(K) V {
	cache := make(map[K]V)
	var mu sync.RWMutex

	return func(key K) V {
		mu.RLock()
		if v, ok := cache[key]; ok {
			mu.RUnlock()
			return v
		}
		mu.RUnlock()

		v := fn(key)
		mu.Lock()
		cache[key] = v
		mu.Unlock()
		return v
	}
}

