package main

import "sync"

func WorkerPool[T any, R any](workers int, jobs []T, fn func(T) R) []R {
	var wg sync.WaitGroup
	results := make([]R, len(jobs))
	ch := make(chan int, len(jobs))

	for i := range jobs {
		ch <- i
	}
	close(ch)

	for w := 0; w < workers; w++ {
		wg.Add(1)
		go func() {
			defer wg.Done()
			for idx := range ch {
				results[idx] = fn(jobs[idx])
			}
		}()
	}

	wg.Wait()
	return results
}

