/**
 * Admin Session — Cookie-based session for admin dashboard access.
 *
 * Uses HMAC-SHA256 signed cookies so the middleware can verify sessions
 * without hitting a database. The signature prevents tampering.
 *
 * Cookie format: <payload>.<signature>
 * Payload: base64url(JSON.stringify({ exp }))
 */

import { createHmac } from "crypto";

const COOKIE_NAME = "__admin_session";
const SESSION_DURATION_S = 8 * 60 * 60; // 8 hours

function getSecret(): string {
  const key = process.env.ADMIN_API_KEY;
  if (!key) throw new Error("ADMIN_API_KEY is not set");
  return key;
}

function sign(payload: string): string {
  return createHmac("sha256", getSecret())
    .update(payload)
    .digest("base64url");
}

/** Create a signed session token with an expiration time. */
export function createSessionToken(): string {
  const exp = Math.floor(Date.now() / 1000) + SESSION_DURATION_S;
  const payload = Buffer.from(JSON.stringify({ exp })).toString("base64url");
  const sig = sign(payload);
  return `${payload}.${sig}`;
}

/** Verify a session token. Returns true if valid and not expired. */
export function verifySessionToken(token: string): boolean {
  try {
    const [payload, sig] = token.split(".");
    if (!payload || !sig) return false;

    const expectedSig = sign(payload);

    // Constant-time comparison
    if (sig.length !== expectedSig.length) return false;
    let mismatch = 0;
    for (let i = 0; i < sig.length; i++) {
      mismatch |= sig.charCodeAt(i) ^ expectedSig.charCodeAt(i);
    }
    if (mismatch !== 0) return false;

    const data = JSON.parse(
      Buffer.from(payload, "base64url").toString("utf-8"),
    );
    if (typeof data.exp !== "number") return false;

    return data.exp > Math.floor(Date.now() / 1000);
  } catch {
    return false;
  }
}

export const ADMIN_SESSION_COOKIE = COOKIE_NAME;
export const ADMIN_SESSION_MAX_AGE = SESSION_DURATION_S;

/**
 * useUtmTracking — Capture and persist UTM parameters across the session.
 *
 * Captures utm_source, utm_medium, utm_campaign, utm_term, utm_content
 * from the URL on first load, persists them in sessionStorage so they
 * survive navigation within the site. Exposes them for form submission.
 *
 * Also captures referrer and landing page for attribution.
 */
import { useEffect, useState } from "react";

export interface UtmParams {
  utmSource: string | null;
  utmMedium: string | null;
  utmCampaign: string | null;
  utmTerm: string | null;
  utmContent: string | null;
  referrer: string | null;
  landingPage: string | null;
}

const STORAGE_KEY = "dc_utm";

const UTM_KEYS = [
  ["utm_source", "utmSource"],
  ["utm_medium", "utmMedium"],
  ["utm_campaign", "utmCampaign"],
  ["utm_term", "utmTerm"],
  ["utm_content", "utmContent"],
] as const;

function captureFromUrl(): UtmParams {
  const params = new URLSearchParams(window.location.search);
  const utm: UtmParams = {
    utmSource: null,
    utmMedium: null,
    utmCampaign: null,
    utmTerm: null,
    utmContent: null,
    referrer: document.referrer || null,
    landingPage: window.location.href,
  };

  for (const [urlKey, stateKey] of UTM_KEYS) {
    const value = params.get(urlKey);
    if (value) {
      utm[stateKey] = value;
    }
  }

  return utm;
}

function loadFromStorage(): UtmParams | null {
  try {
    const stored = sessionStorage.getItem(STORAGE_KEY);
    return stored ? JSON.parse(stored) : null;
  } catch {
    return null;
  }
}

function saveToStorage(utm: UtmParams): void {
  try {
    sessionStorage.setItem(STORAGE_KEY, JSON.stringify(utm));
  } catch {
    // Storage unavailable — silent fail
  }
}

export function useUtmTracking(): UtmParams {
  const [utm, setUtm] = useState<UtmParams>({
    utmSource: null,
    utmMedium: null,
    utmCampaign: null,
    utmTerm: null,
    utmContent: null,
    referrer: null,
    landingPage: null,
  });

  useEffect(() => {
    // Priority: URL params (fresh click) > sessionStorage (persisted)
    const fromUrl = captureFromUrl();
    const hasUrlUtm = UTM_KEYS.some(([_, key]) => fromUrl[key] !== null);

    if (hasUrlUtm) {
      // Fresh click with UTM params — save and use
      saveToStorage(fromUrl);
      setUtm(fromUrl);
    } else {
      // No UTM in URL — check session storage
      const stored = loadFromStorage();
      if (stored) {
        setUtm(stored);
      } else {
        // First visit with no UTM — save referrer/landing page
        saveToStorage(fromUrl);
        setUtm(fromUrl);
      }
    }
  }, []);

  return utm;
}

/**
 * CSRF Protection
 *
 * Double-submit cookie pattern:
 *  1. Server sets a random token in an httpOnly, sameSite=strict cookie
 *  2. API endpoint /api/csrf returns the token for the client to read
 *  3. Client sends the token as X-CSRF-Token header on mutating requests
 *  4. Server validates header matches cookie value
 *
 * This works with Next.js App Router + React client components.
 */

import { NextRequest, NextResponse } from "next/server";
import { randomBytes } from "crypto";

const CSRF_COOKIE_NAME = "__csrf";
const CSRF_HEADER_NAME = "x-csrf-token";
const TOKEN_LENGTH = 32; // 256 bits of entropy

/** Generate a cryptographically secure CSRF token */
export function generateCsrfToken(): string {
  return randomBytes(TOKEN_LENGTH).toString("hex");
}

/** Read the CSRF token from the request cookie */
export function getCsrfTokenFromCookie(req: NextRequest): string | null {
  return req.cookies.get(CSRF_COOKIE_NAME)?.value ?? null;
}

/** Read the CSRF token from the request header */
export function getCsrfTokenFromHeader(req: NextRequest): string | null {
  return req.headers.get(CSRF_HEADER_NAME);
}

/**
 * Validate that the CSRF header matches the cookie.
 * Returns true if valid, false if mismatch or missing.
 */
export function validateCsrfToken(req: NextRequest): boolean {
  const cookieToken = getCsrfTokenFromCookie(req);
  const headerToken = getCsrfTokenFromHeader(req);

  if (!cookieToken || !headerToken) return false;
  if (cookieToken.length !== headerToken.length) return false;

  // Constant-time comparison to prevent timing attacks
  let mismatch = 0;
  for (let i = 0; i < cookieToken.length; i++) {
    mismatch |= cookieToken.charCodeAt(i) ^ headerToken.charCodeAt(i);
  }
  return mismatch === 0;
}

/**
 * Set the CSRF cookie on a response.
 * Call this from the /api/csrf endpoint or middleware.
 */
export function setCsrfCookie(response: NextResponse, token: string): void {
  response.cookies.set(CSRF_COOKIE_NAME, token, {
    httpOnly: true,
    secure: process.env.NODE_ENV === "production",
    sameSite: "strict",
    path: "/",
    maxAge: 60 * 60, // 1 hour
  });
}

/**
 * Date of Birth validation — minimum age enforcement.
 * Validates DOB string (YYYY-MM-DD) and ensures the person is at least 18 years old.
 */
export function validateDob(dob: string): boolean {
  if (typeof dob !== "string") return false;
  const match = dob.match(/^(\d{4})-(\d{2})-(\d{2})$/);
  if (!match) return false;

  const year = parseInt(match[1], 10);
  const month = parseInt(match[2], 10);
  const day = parseInt(match[3], 10);

  // Basic range checks
  if (month < 1 || month > 12) return false;
  if (day < 1 || day > 31) return false;
  if (year < 1900 || year > new Date().getFullYear()) return false;

  // Validate the date is real (e.g. no Feb 30)
  const date = new Date(year, month - 1, day);
  if (
    date.getFullYear() !== year ||
    date.getMonth() !== month - 1 ||
    date.getDate() !== day
  ) {
    return false;
  }

  return isAtLeast18(date);
}

export function isAtLeast18(birthDate: Date): boolean {
  const today = new Date();
  const eighteenYearsAgo = new Date(
    today.getFullYear() - 18,
    today.getMonth(),
    today.getDate(),
  );
  return birthDate <= eighteenYearsAgo;
}

/**
 * Counter — count occurrences in an array, find most common elements
 * createCounter(array) → { counts (Map), get(item), mostCommon(n), entries() }
 */
function createCounter(array) {
  const counts = new Map();

  for (const item of array) {
    counts.set(item, (counts.get(item) || 0) + 1);
  }

  function get(item) {
    return counts.get(item) || 0;
  }

  function mostCommon(n) {
    const sorted = [...counts.entries()].sort((a, b) => b[1] - a[1]);
    return sorted.slice(0, n);
  }

  function entries() {
    return [...counts.entries()];
  }

  return { counts, get, mostCommon, entries };
}

module.exports = { createCounter };

/**
 * IP-Based Rate Limiter
 *
 * Uses an in-memory sliding window approach. Each IP gets a window of
 * timestamps. Requests beyond the limit within the window are rejected.
 * Stale entries are cleaned up automatically to prevent memory leaks.
 */

interface RateLimitEntry {
  timestamps: number[];
}

const store = new Map<string, RateLimitEntry>();

// --- Sliding window with per-IP tracking for API protection ---

/**
 * Check if an IP is rate-limited.
 * @returns { allowed: true } or { allowed: false, retryAfterMs }
 */
export function checkRateLimit(
  ip: string,
  maxRequests: number = 5,
  windowMs: number = 60_000,
): { allowed: true } | { allowed: false; retryAfterMs: number } {
  const now = Date.now();
  const entry = store.get(ip);

  if (!entry) {
    store.set(ip, { timestamps: [now] });
    return { allowed: true };
  }

  // Slide the window — remove timestamps older than windowMs
  entry.timestamps = entry.timestamps.filter((t) => now - t < windowMs);

  if (entry.timestamps.length >= maxRequests) {
    const oldest = entry.timestamps[0];
    const retryAfterMs = windowMs - (now - oldest);
    return { allowed: false, retryAfterMs };
  }

  entry.timestamps.push(now);
  return { allowed: true };
}

/**
 * Extract client IP from a request.
 * Checks x-forwarded-for, x-real-ip, then falls back to "unknown".
 */
export function getClientIp(headers: Headers): string {
  const forwarded = headers.get("x-forwarded-for");
  if (forwarded) {
    // Take the first IP in the chain (original client)
    return forwarded.split(",")[0].trim();
  }
  return headers.get("x-real-ip") || "unknown";
}

// --- Cleanup stale entries every 5 minutes to prevent memory leaks ---
const CLEANUP_INTERVAL = 5 * 60 * 1000;

function cleanup(): void {
  const now = Date.now();
  const maxAge = 10 * 60 * 1000; // Remove entries not seen in 10 minutes
  for (const [ip, entry] of store) {
    const latest = entry.timestamps[entry.timestamps.length - 1] || 0;
    if (now - latest > maxAge) {
      store.delete(ip);
    }
  }
}

setInterval(cleanup, CLEANUP_INTERVAL).unref();

