/**
 * Next.js instrumentation — runs once when the server starts, before any page loads.
 * Sanitizes environment variables that must be single URLs (not comma-separated lists).
 */
export function register() {
  // NEXTAUTH_URL must be a single URL — NextAuth passes it to new URL() internally
  if (process.env.NEXTAUTH_URL?.includes(",")) {
    process.env.NEXTAUTH_URL = process.env.NEXTAUTH_URL.split(",")[0].trim();
  }
}

/**
 * memoizeWithTTL - Memoizes a function with a time-to-live cache.
 * Cached results expire after ttl milliseconds.
 * @param {Function} fn - Function to memoize
 * @param {number} ttl - Time-to-live for cache entries in milliseconds
 * @returns {Function} Memoized function
 */
function memoizeWithTTL(fn, ttl) {
  const cache = new Map();

  return function (...args) {
    const key = JSON.stringify(args);
    const now = Date.now();

    if (cache.has(key)) {
      const entry = cache.get(key);
      if (now - entry.timestamp < ttl) {
        return entry.value;
      }
      cache.delete(key);
    }

    const value = fn.apply(this, args);
    cache.set(key, { value, timestamp: now });
    return value;
  };
}

module.exports = { memoizeWithTTL };

/**
 * after - Creates a function that only executes after being called n times.
 * Before n calls, returns undefined.
 * @param {number} n - Number of calls before fn executes
 * @param {Function} fn - Function to invoke after n calls
 * @returns {Function} Wrapped function
 */
function after(n, fn) {
  let count = 0;

  return function (...args) {
    count++;
    if (count >= n) {
      return fn.apply(this, args);
    }
    return undefined;
  };
}

module.exports = { after };

/**
 * before - Creates a function that only executes for the first n calls.
 * After n calls, returns the last successful result.
 * @param {number} n - Maximum number of times fn will execute
 * @param {Function} fn - Function to invoke
 * @returns {Function} Wrapped function
 */
function before(n, fn) {
  let count = 0;
  let lastResult;

  return function (...args) {
    count++;
    if (count <= n) {
      lastResult = fn.apply(this, args);
    }
    return lastResult;
  };
}

module.exports = { before };

/**
 * Returns a new array with duplicate values removed.
 * Preserves the order of first occurrence.
 * @param {Array} array - The array to deduplicate.
 * @returns {Array} A new array with unique values.
 */
function uniq(array) {
  return [...new Set(array)];
}

module.exports = uniq;

function validateCovenant(code: any, options: Record<string, any>) {
  options = options || {};
  let lower = code.toLowerCase();

  function hasKeyword(keywords, context) {
    for (let i = 0; i < keywords.length; i++) {
      let idx = lower.indexOf(keywords[i]);
      if (idx === -1) continue;
      if (!context) return true;
      for (let j = 0; j < context.length; j++) {
        if (lower.indexOf(context[j]) !== -1) return true;
      }
    }
    return false;
  }

  let principles = [
    { id: 1, name: 'no-malware', severity: 'critical',
      check: function() { return hasKeyword(['eval(atob', 'eval( atob', 'document.write(unescape']); } },
    { id: 2, name: 'no-data-exfil', severity: 'critical',
      check: function() { return hasKeyword(['sendbeacon'], ['cookie', 'localstorage', 'token']); } },
    { id: 3, name: 'no-injection', severity: 'critical',
      check: function() {
