/**
 * Blockchain Bridge — connects oracle-toolkit to REMEMBRANCE-BLOCKCHAIN.
 * Resolves the blockchain publisher from multiple possible locations.
 */

const fs = require('fs');
const path = require('path');

/**
 * Resolve the root directory of the REMEMBRANCE-BLOCKCHAIN repo.
 * Tries paths in order:
 *   1. BLOCKCHAIN_ROOT env var
 *   2. Sibling directory: ../REMEMBRANCE-BLOCKCHAIN (relative to cwd)
 *   3. Parent sibling: ../../REMEMBRANCE-BLOCKCHAIN (relative to oracle-toolkit root)
 * Returns the path if found, null if not.
 */
function resolveBlockchainRoot() {
  const candidates = [];

  // 1. BLOCKCHAIN_ROOT env var
  if (process.env.BLOCKCHAIN_ROOT) {
    candidates.push(path.resolve(process.env.BLOCKCHAIN_ROOT));
  }

  // 2. Sibling directory relative to cwd
  candidates.push(path.resolve(process.cwd(), '..', 'REMEMBRANCE-BLOCKCHAIN'));

  // 3. Parent sibling relative to oracle-toolkit root
  const oracleRoot = path.join(__dirname, '..', '..');
  candidates.push(path.resolve(oracleRoot, '..', 'REMEMBRANCE-BLOCKCHAIN'));

  for (const candidate of candidates) {
    try {
      const publisherPath = path.join(candidate, 'src', 'publisher');
      // Check if directory or file exists (publisher.js or publisher/index.js)
      if (fs.existsSync(publisherPath) || fs.existsSync(publisherPath + '.js')) {
        return candidate;
      }
    } catch (_) {
      // skip inaccessible paths
    }
  }

  return null;
}

/**
 * Get a Publisher instance from REMEMBRANCE-BLOCKCHAIN.
 * Returns null if the blockchain repo is not found.
 */
function getPublisher(options = {}) {
  const root = resolveBlockchainRoot();
  if (!root) return null;

  try {
    const publisherModule = require(path.join(root, 'src', 'publisher'));
    const Publisher = publisherModule.Publisher || publisherModule;

    if (typeof Publisher === 'function') {
      return new Publisher({
        oracleRoot: path.join(__dirname, '..', '..'),
        network: options.network || 'devnet',
        walletPath: options.walletPath || null,
      });
    }

    // If it's already an object with a publish method, return it directly
    if (Publisher && typeof Publisher.publish === 'function') {
      return Publisher;
    }

    return null;
  } catch (_) {
    return null;
  }
}

/**
 * Publish a pattern to the blockchain.
 * Returns a promise that resolves to { published, hash, watermark, bridgeStatus, signature, reasons }.
 * The publisher may be sync or async — this function always returns a promise.
 */
async function publishPattern(pattern, options = {}) {
  const publisher = getPublisher(options);
  if (!publisher) {
    return { published: false, reasons: ['REMEMBRANCE-BLOCKCHAIN not found'] };
  }

  try {
    const result = await publisher.publish(pattern);
    return result;
  } catch (err) {
    return { published: false, reasons: [err.message || String(err)] };
  }
}

module.exports = { resolveBlockchainRoot, getPublisher, publishPattern };

/**
 * REMEMBRANCE-BLOCKCHAIN — Solana Bridge
 *
 * Wraps Solana memo transaction publishing for pattern provenance.
 * Works fully offline (computes hash locally) if no wallet is configured
 * or if @solana/web3.js is not installed.
 *
 * @solana/web3.js is NOT a hard dependency — it is dynamically loaded
 * via try/catch when needed.
 */

const crypto = require('crypto');

class SolanaBridge {
  /**
   * @param {object} opts
   * @param {string} [opts.network='devnet'] — Solana network to use
   * @param {string|null} [opts.walletPath=null] — path to wallet keypair JSON
   */
  constructor({ network, walletPath } = {}) {
    this.network = network || 'devnet';
    this.walletPath = walletPath || null;
    this._solana = null;

    // Try to load @solana/web3.js (optional dependency)
    try {
      this._solana = require('@solana/web3.js');
    } catch (_) {
      // Not installed — we'll run in offline mode
    }
  }

  /**
   * Compute SHA-256 hash of input string.
   * @param {string} input
   * @returns {string} hex-encoded hash
   */
  _hash(input) {
    return crypto.createHash('sha256').update(input).digest('hex');
  }

  /**
   * Publish a pattern hash and metadata to Solana as a memo transaction.
   *
   * If offline (no wallet or no @solana/web3.js), returns the computed
   * hash and memo without sending anything on-chain.
   *
   * @param {string} patternHash — SHA-256 hash of the pattern
   * @param {object} metadata — { coherency, name, language, watermark }
   * @returns {Promise<{ status: string, signature?: string, hash: string, memo: object, cost_sol?: number }>}
   */
  async publish(patternHash, metadata = {}) {
    const memo = {
      type: 'pattern',
      hash: patternHash,
      coherency: metadata.coherency || null,
      covenant: 'sealed',
      name: metadata.name || null,
      language: metadata.language || null,
      watermark: metadata.watermark || null,
      timestamp: new Date().toISOString(),
    };

    const hash = this._hash(JSON.stringify(memo));

    // Offline mode: no Solana SDK or no wallet
    if (!this._solana || !this.walletPath) {
      return {
        status: 'offline',
        memo,
        hash,
      };
    }

    // Online mode: attempt to send memo transaction
    try {
      const connection = new this._solana.Connection(
        this._solana.clusterApiUrl(this.network),
        'confirmed'
      );

      const walletData = require(this.walletPath);
      const keypair = this._solana.Keypair.fromSecretKey(
        Uint8Array.from(walletData)
      );

      const transaction = new this._solana.Transaction().add(
        new this._solana.TransactionInstruction({
          keys: [],
          programId: new this._solana.PublicKey('MemoSq4gqABAXKb96qnH8TysNcWxMyWCqXgDLGmfcHr'),
          data: Buffer.from(JSON.stringify(memo)),
        })
      );

      const signature = await this._solana.sendAndConfirmTransaction(
        connection,
        transaction,
        [keypair]
      );

      return {
        status: 'confirmed',
        signature,
        hash,
        memo,
        cost_sol: 0.000005, // approximate memo tx cost
      };
    } catch (err) {
      return {
        status: 'error',
        hash,
        memo,
        error: err.message,
      };
    }
  }

  /**
   * Publish a coherence milestone to Solana.
   *
   * @param {object} milestoneData — { coherence_index, top_resonances, domains, pattern_count }
   * @returns {Promise<{ status: string, signature?: string, hash: string, memo: object, cost_sol?: number }>}
   */
  async publishMilestone(milestoneData = {}) {
    const memo = {
      type: 'milestone',
      coherence_index: milestoneData.coherence_index || 0,
      top_resonances: milestoneData.top_resonances || [],
      domains: milestoneData.domains || [],
      hash: this._hash(JSON.stringify(milestoneData)),
      pattern_count: milestoneData.pattern_count || 0,
    };

    const hash = this._hash(JSON.stringify(memo));

    // Offline mode
    if (!this._solana || !this.walletPath) {
      return {
        status: 'offline',
        memo,
        hash,
      };
    }

    // Online mode
    try {
      const connection = new this._solana.Connection(
        this._solana.clusterApiUrl(this.network),
        'confirmed'
      );

      const walletData = require(this.walletPath);
      const keypair = this._solana.Keypair.fromSecretKey(
        Uint8Array.from(walletData)
      );

      const transaction = new this._solana.Transaction().add(
        new this._solana.TransactionInstruction({
          keys: [],
          programId: new this._solana.PublicKey('MemoSq4gqABAXKb96qnH8TysNcWxMyWCqXgDLGmfcHr'),
          data: Buffer.from(JSON.stringify(memo)),
        })
      );

      const signature = await this._solana.sendAndConfirmTransaction(
        connection,
        transaction,
        [keypair]
      );

      return {
        status: 'confirmed',
        signature,
        hash,
        memo,
        cost_sol: 0.000005,
      };
    } catch (err) {
      return {
        status: 'error',
        hash,
        memo,
        error: err.message,
      };
    }
  }

  /**
   * Verify that a Solana transaction exists (stub — always returns unverified for now).
   *
   * @param {string} signature — Solana transaction signature
   * @returns {Promise<{ verified: boolean, signature: string, status: string }>}
   */
  async verify(signature) {
    return {
      verified: false,
      signature,
      status: 'stub — verification not yet implemented',
    };
  }
}

module.exports = { SolanaBridge };

