/**
 * Portal Session — Cookie-based session for client portal access.
 *
 * Uses HMAC-SHA256 signed cookies (same approach as admin-session.ts).
 * Payload includes client ID and email for route-level auth.
 *
 * Cookie format: <payload>.<signature>
 * Payload: base64url(JSON.stringify({ id, email, exp }))
 */

import { createHmac } from "crypto";

const COOKIE_NAME = "__portal_session";
const SESSION_DURATION_S = 7 * 24 * 60 * 60; // 7 days

function getSecret(): string {
  // Use a dedicated secret or fall back to NEXTAUTH_SECRET
  const key = process.env.PORTAL_SESSION_SECRET || process.env.NEXTAUTH_SECRET;
  if (!key) throw new Error("PORTAL_SESSION_SECRET or NEXTAUTH_SECRET must be set");
  return key;
}

function sign(payload: string): string {
  return createHmac("sha256", getSecret())
    .update(payload)
    .digest("base64url");
}

export interface PortalSessionData {
  id: number;
  email: string;
  firstName: string;
  lastName: string;
}

/** Create a signed session token for a portal client. */
export function createPortalSessionToken(data: PortalSessionData): string {
  const exp = Math.floor(Date.now() / 1000) + SESSION_DURATION_S;
  const payload = Buffer.from(
    JSON.stringify({ id: data.id, email: data.email, firstName: data.firstName, lastName: data.lastName, exp }),
  ).toString("base64url");
  const sig = sign(payload);
  return `${payload}.${sig}`;
}

/** Verify a portal session token. Returns session data if valid, null otherwise. */
export function verifyPortalSessionToken(token: string): PortalSessionData | null {
  try {
    const [payload, sig] = token.split(".");
    if (!payload || !sig) return null;

    const expectedSig = sign(payload);

    // Constant-time comparison
    if (sig.length !== expectedSig.length) return null;
    let mismatch = 0;
    for (let i = 0; i < sig.length; i++) {
      mismatch |= sig.charCodeAt(i) ^ expectedSig.charCodeAt(i);
    }
    if (mismatch !== 0) return null;

    const data = JSON.parse(
      Buffer.from(payload, "base64url").toString("utf-8"),
    );
    if (typeof data.exp !== "number") return null;
    if (data.exp <= Math.floor(Date.now() / 1000)) return null;

    return {
      id: data.id,
      email: data.email,
      firstName: data.firstName,
      lastName: data.lastName,
    };
  } catch {
    return null;
  }
}

/** Lightweight check for middleware (Edge runtime) — checks expiry only, no HMAC. */
export function isPortalSessionLikelyValid(token: string): boolean {
  try {
    const [payload] = token.split(".");
    if (!payload) return false;
    const json = atob(payload.replace(/-/g, "+").replace(/_/g, "/"));
    const data = JSON.parse(json);
    if (typeof data.exp !== "number") return false;
    return data.exp > Math.floor(Date.now() / 1000);
  } catch {
    return false;
  }
}

export const PORTAL_SESSION_COOKIE = COOKIE_NAME;
export const PORTAL_SESSION_MAX_AGE = SESSION_DURATION_S;

/**
 * Admin Authentication
 *
 * Three authentication methods (checked in order):
 *  1. NextAuth session token — Google OAuth users listed in ADMIN_EMAILS
 *  2. Session cookie (__admin_session) — set by /api/admin/login, HMAC-signed
 *  3. Bearer token (Authorization header) — for programmatic/API access
 *
 * Environment variables:
 *   ADMIN_API_KEY   — required for API key / legacy admin access
 *   ADMIN_EMAILS    — comma-separated Google emails granted admin access
 *   NEXTAUTH_SECRET — required for NextAuth JWT verification
 */

import { NextRequest, NextResponse } from "next/server";
import { getToken } from "next-auth/jwt";
import { verifySessionToken, ADMIN_SESSION_COOKIE } from "./admin-session";

/** Comma-separated list of admin emails (case-insensitive). */
const ADMIN_EMAILS = (process.env.ADMIN_EMAILS ?? "")
  .split(",")
  .map((e) => e.trim().toLowerCase())
  .filter(Boolean);

/**
 * Verify admin authentication.
 *
 * Returns null if authenticated, or a NextResponse with 401/403/503 if not.
 */
export async function verifyAdmin(req: NextRequest): Promise<NextResponse | null> {
  // Method 1: NextAuth JWT — check if Google-authenticated user is an admin
  try {
    const token = await getToken({ req, secret: process.env.NEXTAUTH_SECRET });
    if (token?.email && ADMIN_EMAILS.includes((token.email as string).toLowerCase())) {
      return null; // Authenticated via Google OAuth admin email
    }
  } catch {
    // NextAuth not configured or token invalid — fall through
  }

  // Method 2: Session cookie (from /api/admin/login flow)
  const sessionCookie = req.cookies.get(ADMIN_SESSION_COOKIE)?.value;
  if (sessionCookie && verifySessionToken(sessionCookie)) {
    return null; // Authenticated via session
  }

  // Method 3: Bearer token (for programmatic access)
  const adminKey = process.env.ADMIN_API_KEY;

  if (!adminKey) {
    console.error("[ADMIN AUTH] ADMIN_API_KEY environment variable is not set.");
    return NextResponse.json(
      { success: false, message: "Admin access is not configured." },
      { status: 503 },
    );
  }

  const authHeader = req.headers.get("authorization");
  if (!authHeader) {
    return NextResponse.json(
      { success: false, message: "Authentication required." },
      { status: 401 },
    );
  }

  const [scheme, bearerToken] = authHeader.split(" ");
  if (scheme !== "Bearer" || !bearerToken) {
    return NextResponse.json(
      { success: false, message: "Invalid authorization format. Use: Bearer <token>" },
      { status: 401 },
    );
  }

  // Constant-time comparison to prevent timing attacks
  if (!timingSafeEqual(bearerToken, adminKey)) {
    return NextResponse.json(
      { success: false, message: "Invalid credentials." },
      { status: 403 },
    );
  }

  return null; // Authenticated via bearer token
}

/** Constant-time string comparison */
function timingSafeEqual(a: string, b: string): boolean {
  if (a.length !== b.length) return false;
  let result = 0;
  for (let i = 0; i < a.length; i++) {
    result |= a.charCodeAt(i) ^ b.charCodeAt(i);
  }
  return result === 0;
}

