/**
 * Lead Notification Webhook System
 *
 * Webhooks are configured via environment variables:
 *   WEBHOOK_URLS — comma-separated list of endpoint URLs
 *   WEBHOOK_SECRET — shared secret for HMAC signature verification
 *
 * Each lead submission fires a POST to all configured endpoints with:
 *  - JSON payload of the lead data
 *  - X-Webhook-Signature header (HMAC-SHA256)
 *  - X-Webhook-Event header ("lead.created")
 *  - Retry with exponential backoff (3 attempts)
 */
import { createHmac } from "crypto";
import { withCircuitBreaker, CircuitOpenError } from "./circuit-breaker";

// --- Retry with exponential backoff ---
async function retry<T>(
  fn: () => Promise<T>,
  maxRetries: number = 3,
  delay: number = 1000,
): Promise<T> {
  let lastError: unknown;
  for (let i = 0; i <= maxRetries; i++) {
    try {
      return await fn();
    } catch (err) {
      lastError = err;
      if (i < maxRetries) {
        await new Promise((r) => setTimeout(r, delay * Math.pow(2, i)));
      }
    }
  }
  throw lastError;
}

// --- Result type for typed error handling ---
type Result<T, E = string> = { ok: true; value: T } | { ok: false; error: E };

export interface WebhookPayload {
  event: "lead.created";
  timestamp: string;
  data: {
    leadId: string;
    firstName: string;
    lastName: string;
    dateOfBirth: string;
    email: string;
    phone: string;
    state: string;
    coverageInterest: string;
    createdAt: string;
  };
}

interface WebhookResult {
  url: string;
  status: number;
  success: boolean;
}

/** Sign a payload with HMAC-SHA256 */
function signPayload(payload: string, secret: string): string {
  return createHmac("sha256", secret).update(payload).digest("hex");
}

/** Get configured webhook URLs from environment */
function getWebhookUrls(): string[] {
  const urls = process.env.WEBHOOK_URLS;
  if (!urls) return [];
  return urls
    .split(",")
    .map((u) => u.trim())
    .filter(Boolean);
}

/** Deliver a webhook to a single endpoint with retry */
async function deliverWebhook(
  url: string,
  payload: WebhookPayload,
  secret: string,
): Promise<Result<WebhookResult>> {
  const body = JSON.stringify(payload);
  const signature = secret ? signPayload(body, secret) : "";

  try {
    const response = await withCircuitBreaker(
      () => retry(
        async () => {
          const res = await fetch(url, {
            method: "POST",
            headers: {
              "Content-Type": "application/json",
              "X-Webhook-Event": payload.event,
              "X-Webhook-Signature": signature ? `sha256=${signature}` : "",
              "X-Webhook-Timestamp": payload.timestamp,
            },
            body,
            signal: AbortSignal.timeout(10000),
          });

          if (!res.ok && res.status >= 500) {
            throw new Error(`Server error: ${res.status}`);
          }

          return res;
        },
        3,
        1000,
      ),
      // Per-URL circuit breaker: 3 failures → open for 2 minutes
      { name: `webhook-${new URL(url).hostname}`, failureThreshold: 3, resetTimeout: 120_000 },
    );

    return {
      ok: true,
      value: { url, status: response.status, success: response.ok },
    };
  } catch (err) {
    if (err instanceof CircuitOpenError) {
      console.warn(`[WEBHOOK CIRCUIT OPEN] ${url}: ${err.message}`);
      return { ok: false, error: `${url}: Circuit open — skipping` };
    }
    const message = err instanceof Error ? err.message : "Delivery failed";
    console.error(`[WEBHOOK FAILED] ${url}: ${message}`);
    return { ok: false, error: `${url}: ${message}` };
  }
}

/**
 * Fire webhooks for a new lead submission.
 * Non-blocking — errors are logged but don't affect the API response.
 */
export async function notifyLeadCreated(lead: {
  leadId: string;
  firstName: string;
  lastName: string;
  dateOfBirth: string;
  email: string;
  phone: string;
  state: string;
  coverageInterest: string;
  createdAt: string;
}): Promise<void> {
  const urls = getWebhookUrls();
  if (urls.length === 0) return;

  const secret = process.env.WEBHOOK_SECRET || "";

  const payload: WebhookPayload = {
    event: "lead.created",
    timestamp: new Date().toISOString(),
    data: {
      leadId: lead.leadId,
      firstName: lead.firstName,
      lastName: lead.lastName,
      dateOfBirth: lead.dateOfBirth,
      email: lead.email,
      phone: lead.phone,
      state: lead.state,
      coverageInterest: lead.coverageInterest,
      createdAt: lead.createdAt,
    },
  };

  // Fire all webhooks concurrently (non-blocking)
  const results = await Promise.allSettled(
    urls.map((url) => deliverWebhook(url, payload, secret)),
  );

  const successes = results.filter(
    (r) => r.status === "fulfilled" && r.value.ok,
  ).length;
  const failures = results.length - successes;

  if (failures > 0) {
    console.warn(
      `[WEBHOOKS] ${successes}/${results.length} delivered, ${failures} failed for lead ${lead.leadId}`,
    );
  } else {
    console.log(
      `[WEBHOOKS] ${successes}/${results.length} delivered for lead ${lead.leadId}`,
    );
  }
}

/**
 * Lightweight Sentry Error Reporter
 *
 * Uses Sentry's HTTP envelope API directly instead of the heavy @sentry/nextjs SDK.
 * Parses the DSN to extract the project ID, public key, and ingest URL,
 * then sends error events as envelopes via fetch.
 *
 * Environment variable:
 *  - NEXT_PUBLIC_SENTRY_DSN — Sentry DSN string (e.g. "https://key@o123.ingest.sentry.io/456")
 */

interface ParsedDsn {
  publicKey: string;
  host: string;
  projectId: string;
  envelopeUrl: string;
}

let parsedDsn: ParsedDsn | null = null;
let initialized = false;

/**
 * Parse a Sentry DSN into its component parts.
 *
 * DSN format: https://<public_key>@<host>/<project_id>
 * Envelope endpoint: https://<host>/api/<project_id>/envelope/
 */
function parseDsn(dsn: string): ParsedDsn | null {
  try {
    const url = new URL(dsn);
    const publicKey = url.username;
    const host = url.hostname + (url.port ? `:${url.port}` : "");
    const projectId = url.pathname.replace(/\//g, "");

    if (!publicKey || !projectId) return null;

    return {
      publicKey,
      host,
      projectId,
      envelopeUrl: `${url.protocol}//${host}/api/${projectId}/envelope/`,
    };
  } catch {
    return null;
  }
}

/**
 * Initialize Sentry. Call once at app startup.
 * Safe to call multiple times — subsequent calls are no-ops.
 */
export function initSentry(): void {
  if (initialized) return;
  initialized = true;

  const dsn = process.env.NEXT_PUBLIC_SENTRY_DSN;
  if (!dsn) return;

  parsedDsn = parseDsn(dsn);
  if (!parsedDsn) {
    console.warn("[Sentry] Invalid DSN, error reporting disabled.");
  }
}

/**
 * Build a Sentry envelope payload.
 * Envelope format: header\nitem_header\npayload
 * See: https://develop.sentry.dev/sdk/envelopes/
 */
function buildEnvelope(
  event: Record<string, unknown>,
  dsn: ParsedDsn,
): string {
  const envelopeHeader = JSON.stringify({
    event_id: crypto.randomUUID().replace(/-/g, ""),
    dsn: `https://${dsn.publicKey}@${dsn.host}/${dsn.projectId}`,
    sent_at: new Date().toISOString(),
  });

  const itemHeader = JSON.stringify({
    type: "event",
    content_type: "application/json",
  });

  const payload = JSON.stringify(event);

  return `${envelopeHeader}\n${itemHeader}\n${payload}`;
}

/**
 * Send an event envelope to Sentry.
 */
function sendEnvelope(event: Record<string, unknown>): void {
  if (!parsedDsn) return;

  const body = buildEnvelope(event, parsedDsn);

  // Use sendBeacon for reliability during page unload, fall back to fetch
  if (typeof navigator !== "undefined" && typeof navigator.sendBeacon === "function") {
    const sent = navigator.sendBeacon(parsedDsn.envelopeUrl, body);
    if (sent) return;
  }

  fetch(parsedDsn.envelopeUrl, {
    method: "POST",
    headers: { "Content-Type": "text/plain;charset=UTF-8" },
    body,
    keepalive: true,
  }).catch(() => {
    // Silently ignore — can't report an error about error reporting
  });
}

/**
 * Extract a clean error message and stack trace from an unknown error value.
 */
function normalizeError(error: unknown): { message: string; stack?: string } {
  if (error instanceof Error) {
    return {
      message: error.message,
      stack: error.stack,
    };
  }
  if (typeof error === "string") {
    return { message: error };
  }
  return { message: String(error) };
}

/**
 * Build a Sentry exception event from a stack trace string.
 */
function parseStackFrames(stack?: string): Array<Record<string, unknown>> {
  if (!stack) return [];

  const lines = stack.split("\n").slice(1); // Skip the error message line
  const frames: Array<Record<string, unknown>> = [];

  for (const line of lines) {
    const match = line.match(/at\s+(.+?)\s+\((.+?):(\d+):(\d+)\)/);
    if (match) {
      frames.push({
        function: match[1],
        filename: match[2],
        lineno: parseInt(match[3], 10),
        colno: parseInt(match[4], 10),
      });
      continue;
    }
    const simpleMatch = line.match(/at\s+(.+?):(\d+):(\d+)/);
    if (simpleMatch) {
      frames.push({
        filename: simpleMatch[1],
        lineno: parseInt(simpleMatch[2], 10),
        colno: parseInt(simpleMatch[3], 10),
      });
    }
  }

  return frames.reverse(); // Sentry expects frames in oldest-to-newest order
}

/**
 * Report an error to Sentry.
 *
 * @param error — The error to report (Error, string, or unknown)
 * @param context — Optional extra context to attach to the event
 */
export function captureException(
  error: unknown,
  context?: Record<string, unknown>,
): void {
  if (!parsedDsn) return;

  const { message, stack } = normalizeError(error);
  const frames = parseStackFrames(stack);

  const event: Record<string, unknown> = {
    platform: "javascript",
    level: "error",
    timestamp: Date.now() / 1000,
    environment: process.env.NODE_ENV || "production",
    request: typeof window !== "undefined" ? { url: window.location.href } : undefined,
    exception: {
      values: [
        {
          type: error instanceof Error ? error.constructor.name : "Error",
          value: message.slice(0, 1000),
          stacktrace: frames.length > 0 ? { frames } : undefined,
        },
      ],
    },
    extra: context,
  };

  sendEnvelope(event);
}

/**
 * Report a message to Sentry.
 *
 * @param message — The message text
 * @param level — Severity level (default: "info")
 */
export function captureMessage(
  message: string,
  level: "info" | "warning" | "error" = "info",
): void {
  if (!parsedDsn) return;

  const event: Record<string, unknown> = {
    platform: "javascript",
    level,
    timestamp: Date.now() / 1000,
    environment: process.env.NODE_ENV || "production",
    request: typeof window !== "undefined" ? { url: window.location.href } : undefined,
    message: {
      formatted: message.slice(0, 1000),
    },
  };

  sendEnvelope(event);
}

/**
 * A/B Testing Infrastructure
 *
 * Provides deterministic experiment variant assignment using cookies.
 * Variants are assigned via weighted random selection and persisted
 * in cookies for 30 days to ensure consistent user experience.
 *
 * Conversions are tracked through the analytics layer (analytics.ts).
 */

import { trackEvent } from "./analytics";

// ─── Types ───

export type Experiment = {
  id: string;
  variants: string[];
  weights?: number[];
};

// ─── Cookie Helpers ───

/**
 * Get the value of a cookie by name.
 * Returns null if not found or if running on the server.
 */
function getCookie(name: string): string | null {
  if (typeof document === "undefined") return null;
  const match = document.cookie.match(
    new RegExp("(?:^|;\\s*)" + name.replace(/[.*+?^${}()|[\]\\]/g, "\\$&") + "=([^;]*)"),
  );
  return match ? decodeURIComponent(match[1]) : null;
}

/**
 * Set a cookie with the given name, value, and expiry in days.
 */
function setCookie(name: string, value: string, days: number): void {
  if (typeof document === "undefined") return;
  const expires = new Date(Date.now() + days * 864e5).toUTCString();
  document.cookie = `${name}=${encodeURIComponent(value)}; expires=${expires}; path=/; SameSite=Lax`;
}

// ─── Variant Assignment ───

/**
 * Select a variant using weighted random assignment.
 *
 * @param variants - Array of variant names (e.g. ["control", "variant-a", "variant-b"])
 * @param weights  - Optional array of weights (must match variants length).
 *                   Defaults to equal weighting if omitted.
 * @returns The selected variant name.
 */
function weightedRandom(variants: string[], weights?: number[]): string {
  if (variants.length === 0) {
    throw new Error("[ab-testing] variants array must not be empty");
  }

  // Default to equal weights
  const w = weights && weights.length === variants.length
    ? weights
    : variants.map(() => 1 / variants.length);

  // Normalize weights to sum to 1
  const total = w.reduce((sum, v) => sum + v, 0);
  const normalized = w.map((v) => v / total);

  // Weighted random selection
  const rand = Math.random();
  let cumulative = 0;
  for (let i = 0; i < normalized.length; i++) {
    cumulative += normalized[i];
    if (rand < cumulative) {
      return variants[i];
    }
  }

  // Fallback — should only happen due to floating point rounding
  return variants[variants.length - 1];
}

/**
 * Get the assigned variant for an experiment.
 *
 * If the user already has a cookie for this experiment, returns the stored variant.
 * Otherwise, assigns a new variant using weighted random selection, stores it
 * in a cookie for 30 days, and returns it.
 *
 * @param experimentId - Unique experiment identifier (used as cookie suffix)
 * @param variants     - Array of variant names
 * @param weights      - Optional array of weights for each variant
 * @returns The assigned variant name
 */
export function getVariant(
  experimentId: string,
  variants: string[],
  weights?: number[],
): string {
  const cookieName = `ab_${experimentId}`;

  // Check for existing assignment
  const existing = getCookie(cookieName);
  if (existing && variants.includes(existing)) {
    return existing;
  }

  // Assign new variant
  const variant = weightedRandom(variants, weights);
  setCookie(cookieName, variant, 30);

  // Track the assignment event
  trackEvent({
    event: "experiment_assigned",
    category: "ab_test",
    label: experimentId,
    metadata: { variant },
  });

  return variant;
}

/**
 * Track a conversion event for an experiment.
 *
 * Fires an analytics event with the experiment ID and assigned variant,
 * allowing you to measure which variant drove the conversion.
 *
 * @param experimentId - The experiment that produced the conversion
 * @param variant      - The variant the user was assigned to
 */
export function trackExperimentConversion(
  experimentId: string,
  variant: string,
): void {
  trackEvent({
    event: "experiment_conversion",
    category: "ab_test",
    label: experimentId,
    value: 1,
    metadata: { variant },
  });
}

/**
 * REMEMBRANCE-BLOCKCHAIN — Covenant Gate
 *
 * Checks whether a pattern is eligible for chain publication.
 * This gate does NOT implement the covenant itself — it calls into
 * the oracle toolkit's covenant system for the actual check.
 *
 * The gate enforces four requirements:
 *   1. Covenant sealed (0 violations via oracle toolkit)
 *   2. Coherency score >= 0.8
 *   3. Test code exists and is non-empty
 *   4. No duplicate (name + language not already published)
 */

const path = require('path');

class CovenantGate {
  /**
   * @param {object} opts
   * @param {string} opts.oracleRoot — absolute path to oracle toolkit root
   */
  constructor({ oracleRoot } = {}) {
    this.oracleRoot = oracleRoot || null;
    this.published = new Set();
    this._covenantCheck = null;

    // Try to load the oracle toolkit's covenant checker
    if (this.oracleRoot) {
      try {
        const covenantPath = path.join(this.oracleRoot, 'src', 'covenant');
        const covenant = require(covenantPath);
        if (typeof covenant.covenantCheck === 'function') {
          this._covenantCheck = covenant.covenantCheck;
        }
      } catch (_) {
        // Oracle toolkit not available — will return ineligible
      }
    }
  }

  /**
   * Run the full publication eligibility check for a pattern.
   *
   * @param {object} pattern
   * @param {string} pattern.name — pattern name
   * @param {string} pattern.language — pattern language
   * @param {string} pattern.code — pattern source code
   * @param {string} [pattern.testCode] — test code for the pattern
   * @param {object} pattern.coherencyScore — { total: number, ... }
   * @returns {{ eligible: boolean, reasons: string[], covenantResult: object|null, coherency: number|null }}
   */
  check(pattern) {
    const reasons = [];
    let covenantResult = null;
    let coherency = null;

    // Requirement 1: Covenant check via oracle toolkit
    if (!this._covenantCheck) {
      reasons.push('Oracle toolkit not available');
    } else {
      try {
        covenantResult = this._covenantCheck(pattern.code);
        if (!covenantResult || covenantResult.violations > 0) {
          reasons.push(
            `Covenant not sealed: ${covenantResult ? covenantResult.violations : 'unknown'} violations`
          );
        }
      } catch (err) {
        reasons.push(`Covenant check failed: ${err.message}`);
      }
    }

    // Requirement 2: Coherency score >= 0.8
    if (pattern.coherencyScore && typeof pattern.coherencyScore.total === 'number') {
      coherency = pattern.coherencyScore.total;
      if (coherency < 0.8) {
        reasons.push(`Coherency too low: ${coherency} (minimum 0.8)`);
      }
    } else {
      reasons.push('Missing coherency score');
    }

    // Requirement 3: Test code must exist and be non-empty
    if (!pattern.testCode || (typeof pattern.testCode === 'string' && pattern.testCode.trim().length === 0)) {
      reasons.push('Test code is missing or empty');
    }

    // Requirement 4: No duplicate (name + language)
    const key = `${pattern.name}:${pattern.language}`;
    if (this.published.has(key)) {
      reasons.push(`Duplicate: ${key} already published`);
    }

    const eligible = reasons.length === 0;

    // If eligible, record it in the published set
    if (eligible) {
      this.published.add(key);
    }

    return {
      eligible,
      reasons,
      covenantResult,
      coherency,
    };
  }
}

module.exports = { CovenantGate };

/**
 * API Request Validation
 *
 * Zero-dependency validation. Defines typed schemas for API payloads.
 * Returns structured errors so the API can respond with specific field messages.
 *
 * Pattern: validate(body) → { valid: true, data: T } | { valid: false, errors: string[] }
 */

// --- Shared validators ---

function isString(v: unknown): v is string {
  return typeof v === "string";
}

function validateName(name: unknown): string | null {
  if (!isString(name)) return "Name must be a string.";
  const trimmed = name.trim();
  if (trimmed.length < 2) return "Name must be at least 2 characters.";
  if (trimmed.length > 100) return "Name must be at most 100 characters.";
  if (!/^[a-zA-Z\s'.,-]+$/.test(trimmed)) return "Name contains invalid characters.";
  return null;
}

function validateEmailField(email: unknown): string | null {
  if (!isString(email)) return "Email must be a string.";
  const re = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  if (!re.test(email) || email.length > 254) return "Invalid email address.";
  return null;
}

/** Simple email validation check — exported for use in other routes */
export function isValidEmail(email: string): boolean {
  if (typeof email !== "string") return false;
  const re = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  return re.test(email) && email.length <= 254;
}

function validatePhone(phone: unknown): string | null {
  if (!isString(phone)) return "Phone must be a string.";
  const digits = phone.replace(/\D/g, "");
  if (digits.length !== 10 && !(digits.length === 11 && digits.startsWith("1"))) {
    return "Invalid phone number. Must be a 10-digit US number.";
  }
  return null;
}

function validateDob(dob: unknown): string | null {
  if (!isString(dob)) return "Date of birth must be a string.";
  const match = dob.match(/^(\d{4})-(\d{2})-(\d{2})$/);
  if (!match) return "Invalid date format. Use YYYY-MM-DD.";
  const year = parseInt(match[1], 10);
  const month = parseInt(match[2], 10);
  const day = parseInt(match[3], 10);
  if (month < 1 || month > 12 || day < 1 || day > 31) return "Invalid date.";
  if (year < 1900 || year > new Date().getFullYear()) return "Invalid year.";
  const date = new Date(year, month - 1, day);
  if (date.getFullYear() !== year || date.getMonth() !== month - 1 || date.getDate() !== day) {
    return "Invalid date.";
  }
  const today = new Date();
  const min18 = new Date(today.getFullYear() - 18, today.getMonth(), today.getDate());
  if (date > min18) return "You must be at least 18 years old.";
  return null;
}

const VALID_STATES = new Set([
  "AL","AK","AZ","AR","CA","CO","CT","DE","DC","FL","GA","HI","ID","IL","IN",
  "IA","KS","KY","LA","ME","MD","MA","MI","MN","MS","MO","MT","NE","NV","NH",
  "NJ","NM","NY","NC","ND","OH","OK","OR","PA","RI","SC","SD","TN","TX","UT",
  "VT","VA","WA","WV","WI","WY",
]);

const VALID_COVERAGE = new Set(["term", "whole", "universal", "final-expense", "annuity", "not-sure"]);
const VALID_PURCHASE_INTENT = new Set(["protect-family", "want-protection", "exploring"]);
const VALID_VETERAN_STATUS = new Set(["active-duty", "reserve", "national-guard", "veteran", "non-military"]);
const VALID_MILITARY_BRANCHES = new Set([
  "army", "marine-corps", "navy", "air-force", "space-force",
  "coast-guard", "national-guard", "reserves",
]);

// --- Lead submission schema ---

export interface ValidatedLeadPayload {
  firstName: string;
  lastName: string;
  dateOfBirth: string;
  email: string;
  phone: string;
  state: string;
  coverageInterest: string;
  purchaseIntent: string;
  veteranStatus: string;
  militaryBranch: string;
  tcpaConsent: true;
  privacyConsent: true;
  consentTimestamp: string;
  consentText: string;
  utmSource?: string;
  utmMedium?: string;
  utmCampaign?: string;
  utmTerm?: string;
  utmContent?: string;
}

export type ValidationResult =
  | { valid: true; data: ValidatedLeadPayload }
  | { valid: false; errors: string[] };

/**
 * Validate a lead submission request body.
 * Returns typed validated data on success, or an array of error messages.
 */
export function validateLeadPayload(body: unknown): ValidationResult {
  if (!body || typeof body !== "object") {
    return { valid: false, errors: ["Request body must be a JSON object."] };
  }

  const b = body as Record<string, unknown>;
  const errors: string[] = [];

  // Name fields
  const firstNameErr = validateName(b.firstName);
  if (firstNameErr) errors.push(`First name: ${firstNameErr}`);

  const lastNameErr = validateName(b.lastName);
  if (lastNameErr) errors.push(`Last name: ${lastNameErr}`);

  // Date of birth
  const dobErr = validateDob(b.dateOfBirth);
  if (dobErr) errors.push(`Date of birth: ${dobErr}`);

  // Email
  const emailErr = validateEmailField(b.email);
  if (emailErr) errors.push(emailErr);

  // Phone
  const phoneErr = validatePhone(b.phone);
  if (phoneErr) errors.push(phoneErr);

  // State
  if (!isString(b.state) || !VALID_STATES.has(b.state)) {
    errors.push("Invalid state.");
  }

  // Coverage interest
  if (!isString(b.coverageInterest) || !VALID_COVERAGE.has(b.coverageInterest)) {
    errors.push("Invalid coverage interest.");
  }

  // Purchase intent
  if (!isString(b.purchaseIntent) || !VALID_PURCHASE_INTENT.has(b.purchaseIntent)) {
    errors.push("Invalid purchase intent.");
  }

  // Veteran status
  if (!isString(b.veteranStatus) || !VALID_VETERAN_STATUS.has(b.veteranStatus)) {
    errors.push("Invalid veteran status.");
  }

  // Military branch (required for all military service categories)
  if (b.veteranStatus && b.veteranStatus !== "non-military") {
    if (!isString(b.militaryBranch) || !VALID_MILITARY_BRANCHES.has(b.militaryBranch)) {
      errors.push("Military branch is required for military service members.");
    }
  }

  // Consent
  if (b.tcpaConsent !== true) errors.push("TCPA consent is required.");
  if (b.privacyConsent !== true) errors.push("Privacy policy consent is required.");
  if (!isString(b.consentTimestamp) || !b.consentTimestamp) errors.push("Consent timestamp is required.");
  if (!isString(b.consentText) || !b.consentText) errors.push("Consent text is required.");

  if (errors.length > 0) {
    return { valid: false, errors };
  }

  return {
    valid: true,
    data: {
      firstName: (b.firstName as string).trim(),
      lastName: (b.lastName as string).trim(),
      dateOfBirth: b.dateOfBirth as string,
      email: (b.email as string).trim().toLowerCase(),
      phone: (b.phone as string).replace(/\D/g, "").slice(-10),
      state: b.state as string,
      coverageInterest: b.coverageInterest as string,
      purchaseIntent: b.purchaseIntent as string,
      veteranStatus: b.veteranStatus as string,
      militaryBranch: b.veteranStatus !== "non-military" ? (b.militaryBranch as string) : "",
      tcpaConsent: true,
      privacyConsent: true,
      consentTimestamp: b.consentTimestamp as string,
      consentText: b.consentText as string,
      // Optional UTM fields
      ...(isString(b.utmSource) && b.utmSource ? { utmSource: b.utmSource } : {}),
      ...(isString(b.utmMedium) && b.utmMedium ? { utmMedium: b.utmMedium } : {}),
      ...(isString(b.utmCampaign) && b.utmCampaign ? { utmCampaign: b.utmCampaign } : {}),
      ...(isString(b.utmTerm) && b.utmTerm ? { utmTerm: b.utmTerm } : {}),
      ...(isString(b.utmContent) && b.utmContent ? { utmContent: b.utmContent } : {}),
    },
  };
}

/**
 * Lead Database — Dual-Mode Persistence Layer
 *
 * Adapter pattern:
 * - When DATABASE_URL is set → PostgreSQL via `pg` (node-postgres) with connection pooling
 * - When DATABASE_URL is not set → SQLite via better-sqlite3 (local dev fallback)
 *
 * All exported functions are async (return Promise<Result<...>>).
 */
import path from "path";

// --- Result type for typed error handling ---
type Result<T, E = Error> = { ok: true; value: T } | { ok: false; error: E };

function Ok<T>(value: T): Result<T, never> {
  return { ok: true, value };
}

function Err<E>(error: E): Result<never, E> {
  return { ok: false, error };
}

